import type { Drill } from "./types";

// Lawyer / senior drills, keyed by module slug — 25 per module.
// Law-firm partner / general counsel: advising boards and C-suites on legal risk in
// plain language, client pitches, crisis and regulatory response, litigate-vs-settle
// recommendations, and hard conversations with major clients. Merged into course.ts.
export const LAWYER_SENIOR_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-law-senior-01","level":"senior","profession":"lawyer","title":"The settlement memo that buries the number","scenario":"You are recommending the client settle a contract dispute for up to $2.4M before trial costs escalate. Your draft memo to the CEO opens with four paragraphs of procedural history before the recommendation appears on page two.","task":"Write a 2-3 sentence memo opening that leads with the recommendation and the number.","tips":["Sentence one: settle, at what ceiling, by when.","Procedural history is support — move it below the recommendation.","A CEO decides from the first paragraph; write it so they can."],"focus":["structure","clarity"],"placeholder":"We recommend settling for up to $2.4M before the pretrial conference on March 12."},
    {"id":"lead-law-senior-02","level":"senior","profession":"lawyer","title":"The regulator update the CEO skims","scenario":"The financial regulator has closed its inquiry into your client with no action. You are drafting the email to the CEO, and your instinct is to recap the six-month process before delivering the outcome.","task":"Write a 2-sentence email that puts the outcome in the first line.","tips":["Lead with the result: inquiry closed, no action.","One sentence of what it means; save the narrative for the attached memo.","Good news buried reads like bad news coming."],"focus":["clarity","concision"],"placeholder":"The FCA has closed its inquiry with no enforcement action."},
    {"id":"lead-law-senior-03","level":"senior","profession":"lawyer","title":"The board email on litigation exposure","scenario":"The board asked for your assessment of the class action filed last week. Your honest view: exposure is manageable, roughly $5-8M, and no disclosure obligation is triggered yet. Your draft opens with a summary of the complaint's allegations.","task":"Write the first two sentences of the board email, leading with your assessment.","tips":["Directors want the verdict: how bad, and what must we do now?","The complaint's allegations are context, not the headline.","State the disclosure conclusion explicitly — it is the decision they care about."],"focus":["structure","impact"]},
    {"id":"lead-law-senior-04","level":"senior","profession":"lawyer","title":"The 'can we do this?' answer","scenario":"The head of product asks whether the company can launch the referral program as designed. The answer is yes, with one change to the reward disclosure. Your draft reply walks through the three statutes you analyzed before answering.","task":"Write a reply that answers yes/no in the first sentence, then names the one required change.","tips":["Business teams need the verdict first: yes, no, or yes-if.","Put the single condition right after the answer.","The statutory analysis is available on request — do not lead with it."],"focus":["clarity","audience"],"placeholder":"Yes — you can launch, with one change:"},
    {"id":"lead-law-senior-05","level":"senior","profession":"lawyer","title":"The injunction ruling call","scenario":"The court just denied the preliminary injunction against your client. You have ninety seconds before the CEO's next meeting to tell her what happened and what it means. Your instinct is to explain the judge's reasoning first.","task":"Write the first two sentences you would say on the call, leading with the outcome and its practical effect.","tips":["Outcome first: injunction denied, operations continue.","The practical effect is the second sentence, not the fifth.","Reasoning and appeal risk can wait for the follow-up memo."],"focus":["clarity","impact"],"placeholder":"We won — the injunction was denied, and you can keep shipping."},
    {"id":"lead-law-senior-06","level":"senior","profession":"lawyer","title":"The conflict you must disclose","scenario":"Running conflicts on a new matter for a major client, you found that the firm must decline the engagement. Your draft email to the client's GC spends two paragraphs on how much the firm values the relationship before saying no.","task":"Write a 3-sentence email that states the declination in the first sentence.","tips":["Lead with the decision: we cannot take this matter.","One sentence on why (a conflict), one on what you can offer instead.","Warmth belongs around the point, not in front of it."],"focus":["clarity","structure"]},
    {"id":"lead-law-senior-07","level":"senior","profession":"lawyer","title":"The litigation hold that reads like a memo","scenario":"A lawsuit is now reasonably anticipated and 200 employees must preserve documents starting today. Your draft hold notice opens with the legal standard for spoliation before telling anyone what to do.","task":"Write the first two sentences of the hold notice, leading with the instruction.","tips":["Sentence one: what recipients must do, starting when.","The legal basis follows the instruction, briefly.","Assume most recipients read only the first lines — put the obligation there."],"focus":["clarity","impact"],"placeholder":"Effective immediately, preserve all documents and messages relating to the Meridian contract."},
    {"id":"lead-law-senior-08","level":"senior","profession":"lawyer","title":"The budget overrun heads-up","scenario":"Discovery in the patent case will run $600K over the approved budget because the other side produced four times the expected volume. You need to tell the client's CFO now, but your draft opens with a defense of the original estimate.","task":"Write a 2-3 sentence message that leads with the new number.","tips":["Lead with the revised figure and the driver in one line.","Explaining the original estimate first reads as defensiveness.","End with the decision you need from the CFO, if any."],"focus":["clarity","precision"],"placeholder":"Discovery will run about $600K over budget — the other side produced 4x the expected volume."},
    {"id":"lead-law-senior-09","level":"senior","profession":"lawyer","title":"The pitch follow-up with a buried ask","scenario":"You pitched a prospective client's GC last week and want a decision meeting before their board convenes on the 20th. Your draft follow-up spends a paragraph re-summarizing the pitch before requesting the meeting.","task":"Write a follow-up email that leads with the specific ask and date.","tips":["First line: the meeting you want and by when.","One line of value, not a pitch recap.","A concrete ask is easier to grant than a warm re-summary."],"focus":["clarity","concision"]},
    {"id":"lead-law-senior-10","level":"senior","profession":"lawyer","title":"The discovery win nobody notices","scenario":"The court granted your motion to compel — the other side must now produce the internal emails you believe make your case. Your update to the client walks through the briefing schedule before mentioning the win.","task":"Write a 2-sentence client update that leads with the win and why it matters.","tips":["Headline: motion granted, and the strategic payoff.","The schedule is logistics; the leverage is the news.","Say what changes in the case, not just what the court ordered."],"focus":["impact","clarity"],"placeholder":"The court granted our motion — they must produce the internal emails by June 5."},
    {"id":"lead-law-senior-11","level":"senior","profession":"lawyer","title":"The self-report recommendation","scenario":"Your internal investigation found conduct the company should disclose to the regulator, and doing so early likely cuts the penalty substantially. Your draft memo to the audit committee builds the case chronologically for five pages before recommending self-reporting.","task":"Write the memo's opening sentence stating the recommendation and the key reason.","tips":["Committees read the first sentence and the last page — put the recommendation in both.","Pair the recommendation with the strongest single reason.","The chronology supports; it does not lead."],"focus":["structure","impact"],"placeholder":"We recommend self-reporting to the regulator within 30 days:"},
    {"id":"lead-law-senior-12","level":"senior","profession":"lawyer","title":"The deal-closing confirmation","scenario":"The acquisition signed and closed an hour ago after a tense final week. Your closing email to the client's CEO drafts itself as a tour of the last-minute issues your team resolved.","task":"Write a 2-sentence closing email that leads with the news.","tips":["First line: signed and closed.","One line on the immediate next step (funds flow, announcements).","The war stories can wait for the closing dinner."],"focus":["concision","clarity"]},
    {"id":"lead-law-senior-13","level":"senior","profession":"lawyer","title":"The termination advice with the verdict last","scenario":"The client asked whether they can terminate their largest supplier contract for cause. Your view: yes, but only after a 30-day cure notice, and terminating without it hands the supplier a claim. Your draft explains the contract's notice mechanics for three paragraphs first.","task":"Rewrite the opening so the verdict and the one condition come first.","tips":["Lead with yes-if: terminable, after the 30-day cure notice.","Name the risk of skipping the condition in sentence two.","Clause-by-clause mechanics go below the line."],"focus":["clarity","structure"],"placeholder":"Yes, you can terminate for cause — but only after serving the 30-day cure notice."},
    {"id":"lead-law-senior-14","level":"senior","profession":"lawyer","title":"The whistleblower escalation","scenario":"A credible whistleblower complaint names a senior vice president. Company policy requires you to brief the audit committee chair within 24 hours. Your draft message opens by describing the complaint intake process.","task":"Write a 2-3 sentence message to the chair that leads with what happened and what you propose.","tips":["First sentence: a credible complaint, who it concerns, received when.","Second: the immediate step you propose (outside counsel, preservation).","Process descriptions dilute urgency — cut them."],"focus":["impact","structure"]},
    {"id":"lead-law-senior-15","level":"senior","profession":"lawyer","title":"The two-option decision email","scenario":"The client must choose by Friday: accept the arbitration demand or remove the case to court, and the choice shapes cost and confidentiality. Your draft explains the dispute's background before presenting the fork.","task":"Write an email opening that leads with the decision needed and the deadline, then frames the two options in one line each.","tips":["Open with the decision and the date — that is the reader's job.","Give each option one line: cost, speed, confidentiality.","State your recommendation; a menu without a pick shirks the work."],"focus":["structure","clarity"],"placeholder":"You need to choose by Friday: arbitrate or go to court. We recommend arbitration."},
    {"id":"lead-law-senior-16","level":"senior","profession":"lawyer","title":"The mediation debrief","scenario":"Yesterday's mediation ended without a deal, but the other side dropped their demand from $10M to $6.5M — real movement. Your update to the client opens with a blow-by-blow of the sessions.","task":"Write the first two sentences of the update, leading with the headline movement and your read.","tips":["Lead with what changed: demand down 35%.","Your read — they want to settle — is the second sentence.","Session chronology is an appendix, not an opener."],"focus":["clarity","impact"],"placeholder":"No deal yet, but real progress: their demand dropped from $10M to $6.5M."},
    {"id":"lead-law-senior-17","level":"senior","profession":"lawyer","title":"The client alert that buries the obligation","scenario":"A new data-privacy rule takes effect in 90 days and requires your clients to update their vendor contracts. Your draft alert opens with the legislative history of the rule.","task":"Write the alert's first two sentences, leading with what clients must do and by when.","tips":["Clients scan alerts for one thing: do I need to act?","Put the obligation and the date in sentence one.","Legislative history convinces no one to keep reading."],"focus":["audience","clarity"]},
    {"id":"lead-law-senior-18","level":"senior","profession":"lawyer","title":"The weekly litigation dashboard","scenario":"You send the GC a Friday summary across nine active matters. This week only one thing changed materially: the Delaware case got a trial date in March. Your draft gives each matter equal space.","task":"Write the summary's opening line, leading with the one material change.","tips":["Lead with what changed; list what did not in one line.","Equal space for unequal news hides the signal.","Name the date — 'trial scheduled' without it is half a headline."],"focus":["concision","structure"],"placeholder":"One material change this week: the Delaware case is set for trial March 9."},
    {"id":"lead-law-senior-19","level":"senior","profession":"lawyer","title":"The IP notice on the CEO's desk","scenario":"A competitor sent a patent infringement notice targeting your client's flagship product. Your assessment: the claim looks weak, but the response deadline is real and a considered reply beats silence. Your draft email opens with a technical summary of the patent.","task":"Write a 2-3 sentence email to the CEO leading with your assessment and the required action.","tips":["First line: the claim is weak, but we must respond by the date.","Separate your read (weak claim) from the obligation (respond).","Patent mechanics belong in the attachment."],"focus":["clarity","impact"]},
    {"id":"lead-law-senior-20","level":"senior","profession":"lawyer","title":"The ask to opposing counsel","scenario":"You need opposing counsel to agree to a two-week extension on expert disclosures, and you are prepared to reciprocate on their pending deposition request. Your draft email meanders through scheduling difficulties first.","task":"Write an email that leads with the specific request and the trade in the first two sentences.","tips":["Ask plainly in sentence one: two weeks on expert disclosures.","Put the reciprocal offer immediately after — it is why they will say yes.","Scheduling woes read as weakness; cut them."],"focus":["clarity","concision"],"placeholder":"We're requesting a two-week extension on expert disclosures — and we'll agree to your deposition dates in exchange."},
    {"id":"lead-law-senior-21","level":"senior","profession":"lawyer","title":"The practice-group staffing ask","scenario":"Your group just won a major insurer as a client, and you need two associates reassigned within a month to staff it. Your note to the managing partner celebrates the win for a paragraph before mentioning staffing.","task":"Write a 2-3 sentence note that pairs the news with the ask up front.","tips":["Headline and ask can share the first sentence.","Quantify the ask: two associates, by when.","The managing partner acts on requests, not celebrations."],"focus":["clarity","impact"]},
    {"id":"lead-law-senior-22","level":"senior","profession":"lawyer","title":"The adverse ruling text message","scenario":"The court granted partial summary judgment against your client — two of five claims survive to trial. The GC is boarding a flight and asked for a one-text update.","task":"Write a 1-2 sentence text that leads with the outcome and the bottom line for trial.","tips":["Outcome, then what it means for exposure — in under 40 words.","No procedural vocabulary the GC must decode on a phone.","Say when the fuller memo is coming."],"focus":["concision","clarity"],"placeholder":"Mixed ruling: 3 of 5 claims dismissed. The two that survive carry most of the exposure. Memo tonight."},
    {"id":"lead-law-senior-23","level":"senior","profession":"lawyer","title":"The engagement-scope question","scenario":"A longtime client keeps sending employment questions under an engagement scoped only to commercial contracts. You need them to either expand the scope or route those questions elsewhere. Your draft opens by praising the relationship.","task":"Write a message that leads with the scope issue and the choice you are offering.","tips":["Name the issue in sentence one: these questions are outside our current scope.","Offer the two paths immediately: expand the engagement or refer out.","Do not make them infer the point from the pleasantries."],"focus":["clarity","structure"]},
    {"id":"lead-law-senior-24","level":"senior","profession":"lawyer","title":"The verdict voicemail","scenario":"The jury returned a defense verdict — your client owes nothing. The CEO is unreachable, and you are leaving a voicemail. Old habit says to start with 'the jury deliberated for six hours and...'","task":"Write the first two sentences of the voicemail, leading with the result.","tips":["Say the result in the first five words.","Second sentence: the one immediate implication (no payment, no appeal filed yet).","A voicemail may get 15 seconds of attention — front-load it."],"focus":["clarity","impact"],"placeholder":"We won — complete defense verdict, the company owes nothing."},
    {"id":"lead-law-senior-25","level":"senior","profession":"lawyer","title":"The renewal ask hiding behind gratitude","scenario":"Your firm's largest client engagement expires next month and you want a three-year renewal on updated terms. Your draft letter spends its first page thanking them for the relationship.","task":"Write an opening that leads with the renewal proposal while staying gracious.","tips":["Pair the ask with the appreciation in the first two lines — do not stack gratitude in front of it.","Name the term and the one improvement you are proposing.","Confidence in the ask signals confidence in the work."],"focus":["clarity","audience"]}
  ],
  "start-with-the-audience": [
    {"id":"audience-law-senior-01","level":"senior","profession":"lawyer","title":"Indemnification cap for the sales team","scenario":"Sales keeps agreeing to uncapped indemnities to close deals, and you need them to stop. Your draft guidance quotes the model clause and defines 'consequential damages.' The sales team needs to know what to say in a negotiation, not the doctrine.","task":"Write 2-3 sentences of guidance a salesperson could actually use on a call.","tips":["Translate the clause into a negotiating position: what to offer, where the floor is.","Give them the words: a sentence they can say to the customer.","Cut every term a non-lawyer would have to look up."],"focus":["audience","clarity"],"placeholder":"When a customer asks for unlimited liability, offer this instead:"},
    {"id":"audience-law-senior-02","level":"senior","profession":"lawyer","title":"The breach exposure slide for the board","scenario":"You are presenting the data-breach legal exposure to the board. Your draft slide lists statutes: state notification laws, the FTC Act, contractual claims. Directors want three things: how much, how likely, what we are doing.","task":"Rewrite the slide's message as 2-3 sentences answering the board's actual questions.","tips":["Lead with the range and the likelihood, not the legal theories.","Statute names mean nothing to directors; consequences do.","End with the mitigation already underway — boards want to hear control."],"focus":["audience","impact"],"placeholder":"Our realistic exposure is $3-7M, driven mostly by customer notification costs."},
    {"id":"audience-law-senior-03","level":"senior","profession":"lawyer","title":"Explaining privilege before the interviews","scenario":"You are about to interview employees for an internal investigation and must give the standard warning: you represent the company, not them, and the company controls the privilege. Your draft recites the formal language, which tends to frighten people into silence.","task":"Write a 3-4 sentence plain-language version of the warning that is accurate but human.","tips":["Say plainly who you work for and who decides what stays confidential.","Accuracy is non-negotiable; jargon is not.","A frightened witness helps no one — keep the tone steady, not soft."],"focus":["audience","precision"]},
    {"id":"audience-law-senior-04","level":"senior","profession":"lawyer","title":"'Granted in part' for the CEO","scenario":"The court granted the motion to dismiss in part: the fraud claim is out, the contract claim survives. You start typing 'the court granted defendant's 12(b)(6) motion as to count II...' The CEO will not parse that.","task":"Write a 2-sentence translation of the ruling for the CEO.","tips":["Name what died, what survives, and what it does to exposure.","One court-procedure term maximum, and only if you define it in the same breath.","The CEO's question is 'better or worse for us?' — answer it."],"focus":["audience","clarity"],"placeholder":"Good news on balance: the fraud claim — the one with punitive damages — is out."},
    {"id":"audience-law-senior-05","level":"senior","profession":"lawyer","title":"Force majeure for the head of operations","scenario":"A port strike is delaying your client's inbound shipments, and the ops director asks whether the supplier can hide behind the force majeure clause. Your analysis is nuanced, but the ops director needs to decide today whether to book alternative freight.","task":"Write a 2-3 sentence answer keyed to the decision the ops director faces.","tips":["Anchor on their decision: book alternative freight or wait.","Give the practical answer first, the clause reading second.","'It depends' is only acceptable with a decision rule attached."],"focus":["audience","clarity"]},
    {"id":"audience-law-senior-06","level":"senior","profession":"lawyer","title":"The associate memo the client can't read","scenario":"A senior associate wrote a technically excellent 12-page memo on successor liability. You are forwarding the conclusion to the client's CFO, who has asked one question: if we buy these assets, do we inherit their lawsuits?","task":"Write the 2-3 sentence cover note that answers the CFO's question directly.","tips":["Answer the question as asked: yes, no, or under these conditions.","Keep the memo attached for the diligence file; the note carries the meaning.","Use the CFO's words ('inherit their lawsuits'), not the doctrine's."],"focus":["audience","clarity"],"placeholder":"Short answer: no, you don't inherit their lawsuits — with two exceptions to manage."},
    {"id":"audience-law-senior-07","level":"senior","profession":"lawyer","title":"Consent requirements for marketing","scenario":"New privacy rules require opt-in consent before the marketing team can use purchase history for targeted campaigns. Your draft guidance explains the lawful-basis framework. Marketing needs to know what changes about their Tuesday campaign send.","task":"Write 2-3 sentences telling marketing exactly what they can and cannot do now.","tips":["Frame it as their workflow: this campaign, this list, this button.","Give a bright line, not a framework.","Name whom to ask when a case is unclear — that is part of the guidance."],"focus":["audience","clarity"]},
    {"id":"audience-law-senior-08","level":"senior","profession":"lawyer","title":"The litigation hold, engineer edition","scenario":"Your standard hold notice is drafted for office staff. Now it must reach 40 engineers whose relevant material lives in Slack, Jira, and personal notebooks — and who auto-delete aggressively. The legal boilerplate will not change their behavior.","task":"Rewrite the core instruction in 2-3 sentences an engineer will act on.","tips":["Name their actual tools: Slack, Jira, branches, notebooks.","Tell them what to stop doing (auto-delete, cleanup scripts) — behavior, not categories.","Explain the one-line why: courts punish deletion even when innocent."],"focus":["audience","precision"],"placeholder":"Starting now, don't delete anything related to Project Atlas — including Slack threads and Jira tickets."},
    {"id":"audience-law-senior-09","level":"senior","profession":"lawyer","title":"The earn-out dispute for the founder","scenario":"Your client, a first-time founder, sold her company and the buyer is disputing the earn-out calculation. Your draft update discusses EBITDA adjustment mechanics and the accountant-referral clause. She wants to know: am I getting my $4M, and when?","task":"Write a 2-3 sentence update answering her question in her terms.","tips":["Answer money and timing first; mechanics later.","She has no deals background — one plain sentence on what the fight is actually about.","Give her the realistic range, not the theoretical one."],"focus":["audience","clarity"]},
    {"id":"audience-law-senior-10","level":"senior","profession":"lawyer","title":"Same facts, two rooms","scenario":"You must describe the compliance failure twice today: to the regulator this morning, to the board this afternoon. The facts cannot change, but the framing must — the regulator needs candor and remediation detail; the board needs exposure and decisions.","task":"Write the opening 2 sentences of the board version, calibrated to that room.","tips":["Pick the primary audience per document — never blend the two.","For the board: what it costs, what you have already fixed, what you need from them.","Consistency of facts across audiences is a legal requirement, not just good practice."],"focus":["audience","structure"]},
    {"id":"audience-law-senior-11","level":"senior","profession":"lawyer","title":"Non-compete reality check for HR","scenario":"The HR director wants to enforce a non-compete against a departing manager who joined a competitor. Enforceability in your state is shaky, and litigation would likely cost more than it protects. Your draft opens with a survey of state non-compete law.","task":"Write a 2-3 sentence answer built around HR's decision, not the doctrine.","tips":["Lead with the practical call: worth pursuing or not, and why in one clause.","Translate 'shaky enforceability' into odds and cost.","Offer the alternative that actually protects them (confidentiality demand letter)."],"focus":["audience","impact"],"placeholder":"I'd advise against suing: enforcement odds here are poor and the fight costs more than it protects."},
    {"id":"audience-law-senior-12","level":"senior","profession":"lawyer","title":"The arbitration clause in the support script","scenario":"Customers are calling to ask why the new terms of service force disputes into arbitration. Support needs two sentences they can say verbatim that are accurate, calm, and do not create new legal statements the company must stand behind.","task":"Write the 2-sentence customer-safe explanation for the support script.","tips":["Every word will be repeated thousands of times — draft to be quoted.","Accurate and neutral: what arbitration is, what the customer can still do.","No promises, no legal conclusions, no 'this benefits you' spin."],"focus":["audience","precision"]},
    {"id":"audience-law-senior-13","level":"senior","profession":"lawyer","title":"Materiality for the disclosure committee","scenario":"The disclosure committee — half of whom are not lawyers — must decide whether the pending lawsuit needs to be disclosed in the quarterly filing. Your draft explains the materiality standard in case-law terms. They need a usable test for this decision, today.","task":"Write 2-3 sentences giving the committee a plain-language way to apply the standard to this lawsuit.","tips":["Turn the standard into a question they can answer: would a reasonable investor care?","Apply it to these facts — do not leave the application as an exercise.","State your recommendation; the committee decides, but you advise."],"focus":["audience","clarity"]},
    {"id":"audience-law-senior-14","level":"senior","profession":"lawyer","title":"Pitching the CFO, not the GC","scenario":"Your pitch deck for a new client was written for their GC — case citations, bench strength, doctrinal depth. You just learned the CFO makes this decision. The CFO cares about predictable spend, risk reduction, and business disruption.","task":"Rewrite your pitch's opening 2-3 sentences for the CFO.","tips":["Lead with cost predictability and outcomes, not credentials.","Translate 'we win motions' into 'disputes end faster and cheaper.'","One proof point with a number beats three practice-group descriptions."],"focus":["audience","impact"],"placeholder":"Our fixed-fee model means your litigation spend is set in January and doesn't move."},
    {"id":"audience-law-senior-15","level":"senior","profession":"lawyer","title":"'Without prejudice' for the exec in the room","scenario":"Your client's COO will join tomorrow's settlement discussion, her first. You need to brief her on what 'without prejudice' means for what she can say — practically, not doctrinally — in under a minute.","task":"Write the 2-3 sentence briefing you would give her.","tips":["Frame it as rules of the room: what is safe to say, what is not.","Skip the evidentiary theory; give her the operating consequence.","Include the one trap: admissions outside the protected discussion."],"focus":["audience","clarity"]},
    {"id":"audience-law-senior-16","level":"senior","profession":"lawyer","title":"The claim-construction ruling for investor relations","scenario":"The court issued a claim-construction ruling in your client's patent case that substantially favors your side. IR needs language for analyst questions. Your draft says the court 'adopted our construction of the disputed terms' — meaningless outside the courtroom.","task":"Write 1-2 sentences IR can use with analysts.","tips":["Translate the ruling into its business consequence: the case got stronger/weaker for us.","IR language must survive being quoted out of context — keep it factual.","No triumphalism; the case is still live."],"focus":["audience","precision"]},
    {"id":"audience-law-senior-17","level":"senior","profession":"lawyer","title":"Sanctions screening for procurement","scenario":"New sanctions rules mean procurement must screen suppliers in two additional jurisdictions before contracting. Your draft circular cites the executive orders. The procurement team needs to know: which suppliers, checked how, before what step.","task":"Write 2-3 sentences of operational guidance for the procurement team.","tips":["Give them the workflow change: at which step the check happens and what tool to use.","Name the trigger conditions concretely (supplier country, ownership).","Legal citations go in a footnote they will never read — and that is fine."],"focus":["audience","clarity"],"placeholder":"Before signing any supplier in [regions], run the new screening check first —"},
    {"id":"audience-law-senior-18","level":"senior","profession":"lawyer","title":"Making 'it depends' usable","scenario":"A product manager asks whether user testimonials can appear in ads. The honest answer depends on substantiation, typicality disclosures, and material connections. Answering 'it depends' with a memo attachment will make product stop asking legal at all.","task":"Write a 2-3 sentence answer that gives a usable rule plus the exception to flag.","tips":["Convert the analysis into a default rule: safe if X, ask us when Y.","Keep the yes path easy — that is what keeps legal in the loop.","One concrete example of each side beats abstract criteria."],"focus":["audience","clarity"]},
    {"id":"audience-law-senior-19","level":"senior","profession":"lawyer","title":"Cross-border data transfer for the IT lead","scenario":"The IT lead wants to migrate customer data to a cloud region in another country and asks if it is allowed. Your analysis involves adequacy decisions and contractual safeguards. The IT lead needs to know: can we migrate, what must be in place first, and how long that takes.","task":"Write a 2-3 sentence answer structured around the migration decision.","tips":["Answer in the IT lead's units: allowed/blocked, prerequisites, lead time.","Name the one document that must exist before migration starts.","Offer a checkpoint, not a treatise: 'send me the vendor name and I'll confirm in a day.'"],"focus":["audience","structure"]},
    {"id":"audience-law-senior-20","level":"senior","profession":"lawyer","title":"Injunction risk before the campaign","scenario":"Marketing is launching a comparative ad campaign Thursday. A competitor has sued over less. Your view: the claims are defensible but one specific comparison invites a fight. Marketing hears 'legal risk' constantly and has learned to ignore it.","task":"Write a 2-3 sentence warning that lands, framed in marketing's stakes.","tips":["Name their stake: an injunction pulls the whole campaign mid-flight, not just one ad.","Isolate the one comparison to fix — global warnings get discounted.","Give the fix, not just the flag: change this line and launch on time."],"focus":["audience","impact"],"placeholder":"You can launch Thursday if we change one line — the price comparison is the piece that gets us sued."},
    {"id":"audience-law-senior-21","level":"senior","profession":"lawyer","title":"The audit letter, calibrated twice","scenario":"The auditors requested the standard litigation letter, and separately your CEO asked what it will say. The auditor version follows the accounting-standard formula; the CEO version must convey the same substance in plain terms without creating an inconsistent record.","task":"Write the 2-sentence CEO version of what the audit letter will say.","tips":["Same facts, different altitude: the CEO needs conclusions and ranges, not the formula.","Never let the informal version say more (or less) than the formal one.","Flag anything in the letter the CEO will be asked about by the audit committee."],"focus":["audience","precision"]},
    {"id":"audience-law-senior-22","level":"senior","profession":"lawyer","title":"The alert your smallest clients can use","scenario":"Your firm's alert on the new e-signature rules was written for sophisticated GCs. It is also going to 300 small-business owner clients with no legal staff. For them it needs to say: what changed, does it affect me, what do I do.","task":"Rewrite the alert's opening 2-3 sentences for the small-business owners.","tips":["Assume no legal vocabulary and five minutes of attention.","Lead with the self-test: 'if you sign contracts electronically, this affects you.'","One action, one deadline, one contact."],"focus":["audience","clarity"],"placeholder":"If your business signs contracts electronically, a new rule affects you starting July 1."},
    {"id":"audience-law-senior-23","level":"senior","profession":"lawyer","title":"The joint-defense explainer","scenario":"Your client and a co-defendant are entering a joint defense agreement. The co-defendant's COO asks bluntly: 'so we're on the same team now?' The true answer is more careful — aligned today, potentially adverse tomorrow.","task":"Write a 2-3 sentence answer that is honest about the limits without souring cooperation.","tips":["Correct the 'same team' frame gently but clearly — overselling this creates real risk.","Give the operating rule: what can be shared, through whom.","Name the exit condition plainly: if interests split, the agreement ends."],"focus":["audience","precision"]},
    {"id":"audience-law-senior-24","level":"senior","profession":"lawyer","title":"Deposition prep for a first-time witness","scenario":"Your client's VP of engineering is being deposed next month — his first time. Your standard prep outline is written in litigation vocabulary: objections, privilege, the record. He is anxious and needs to understand what the day is actually like.","task":"Write the first 3 sentences of your prep note, translated for a first-time witness.","tips":["Describe the room and the rhythm before the rules.","Convert each rule into behavior: 'wait for the full question, then answer only it.'","Address the anxiety directly — a calm witness is the legal strategy."],"focus":["audience","clarity"]},
    {"id":"audience-law-senior-25","level":"senior","profession":"lawyer","title":"The lawsuit at the all-hands","scenario":"The company is being sued publicly, employees are reading headlines, and the CEO asked you to say a few words at the all-hands. Legal instinct says say nothing; leadership reality says silence breeds rumor. You have 60 seconds.","task":"Write the 3-4 sentences you would say to all employees.","tips":["Acknowledge what they have read; do not pretend it is not news.","Say what you can say, and name why you cannot say more — that honesty builds trust.","Give them the one behavior you need: refer press questions, keep documents.","Nothing you say can be a fact you would not repeat under oath."],"focus":["audience","impact"]}
  ],
  "structure-that-carries": [
    {"id":"structure-law-senior-01","level":"senior","profession":"lawyer","title":"The litigation portfolio in one idea","scenario":"The board wants a review of all eleven active matters. Your draft goes case by case, and directors get lost by matter four. The portfolio actually tells one story: exposure is concentrated in two cases, and everything else is noise.","task":"Write the governing sentence for the memo, then name the 3 buckets you would organize the eleven matters into.","tips":["One governing idea at the top: where the real exposure sits.","Group by what the board must do — decide, watch, ignore — not by filing date.","Each bucket gets one summary sentence; cases are the evidence within it."],"focus":["structure","clarity"],"placeholder":"Our litigation exposure is concentrated in two matters; the other nine are routine."},
    {"id":"structure-law-senior-02","level":"senior","profession":"lawyer","title":"SCQA for the pitch meeting","scenario":"You are pitching a manufacturer facing a wave of product-liability suits across five states. Your usual opener is the firm's credentials. SCQA would start where they are: their situation, the complication they feel, the question that keeps their GC up at night.","task":"Write the pitch opening as SCQA in 4 sentences: Situation, Complication, Question, and your Answer.","tips":["Situation: their world, stated so they nod.","Complication: what changed — the wave of suits and inconsistent defenses.","Question: the one their board is asking; Answer: your coordinated-defense approach in one line."],"focus":["structure","audience"]},
    {"id":"structure-law-senior-03","level":"senior","profession":"lawyer","title":"PREP: 'Should we settle?'","scenario":"On tomorrow's call the client CEO will ask point-blank whether to settle the distributor lawsuit. You have a view: yes, before depositions start. You want a spoken answer that holds together under interruption.","task":"Script a PREP answer — Point, Reason, Example, Point — in 4-5 sentences you could say aloud.","tips":["Point first: settle, and the window.","One reason, not four: depositions multiply cost and risk of bad facts.","The example makes it real: what happened in the comparable case you handled.","Restate the point in different words to close."],"focus":["structure","impact"],"placeholder":"Yes — settle before depositions begin, and here's why."},
    {"id":"structure-law-senior-04","level":"senior","profession":"lawyer","title":"Twelve diligence findings, three buckets","scenario":"Your team's diligence on the acquisition target surfaced twelve issues: expired permits, two customer contracts with change-of-control clauses, an unregistered trademark, pending wage claims, and more. The client call is in an hour and a twelve-item list will bury the two that matter.","task":"Define 3 buckets for the findings and write the one-sentence headline for each.","tips":["Bucket by consequence: deal-blockers, price-adjusters, post-closing cleanup.","The bucket names should tell the client what to do about them.","Order buckets by severity — lead with what could kill the deal."],"focus":["structure","clarity"]},
    {"id":"structure-law-senior-05","level":"senior","profession":"lawyer","title":"The crisis-response memo skeleton","scenario":"A regulator just announced an industry-wide investigation naming your client. The CEO wants a response plan by 6pm. Under time pressure your team's draft is a chronological to-do list. It needs architecture: what we know, what we must do now, what we decide later.","task":"Write the memo's 3 section headers as full sentences, each carrying its section's message.","tips":["Headers should assert, not label: 'We must preserve documents today' beats 'Document preservation.'","Sequence by urgency: today, this week, this month.","A reader skimming only headers should get the whole plan."],"focus":["structure","impact"],"placeholder":"1. What we know: the investigation targets pricing practices, and we are one of six companies named."},
    {"id":"structure-law-senior-06","level":"senior","profession":"lawyer","title":"The comment letter that rambles","scenario":"Your client wants to oppose a proposed regulation, and your draft comment letter raises nine objections in the order the team thought of them. Regulators reward letters with one clear position supported by organized argument.","task":"Write the letter's position statement, then group the nine objections into 2-3 argument headings.","tips":["One governing position up front: what the agency should change and why.","Group objections by theme (cost, workability, legal authority) — nine parallel points read as noise.","Cut objections that dilute: three strong beat nine mixed."],"focus":["structure","concision"]},
    {"id":"structure-law-senior-07","level":"senior","profession":"lawyer","title":"Untangling the advice email","scenario":"You dictated advice on a joint-venture exit while traveling, and the transcript wanders: tax angles, then the buy-sell clause, back to tax, a thought about timing, then valuation. The client is a private-equity director who reads in F-pattern skims.","task":"Reorganize the advice into a message with one conclusion up top and 3 grouped support points.","tips":["Find the buried conclusion — it is usually in your final paragraph.","Merge the scattered tax mentions into one point.","Each support point: assertion first, detail second."],"focus":["structure","clarity"]},
    {"id":"structure-law-senior-08","level":"senior","profession":"lawyer","title":"Decide, on-track, watch","scenario":"Your monthly report to the client's GC covers seven matters in prose. The GC forwarded last month's version asking 'what do you actually need from me?' The report never separated decisions needed from status.","task":"Restructure the report into three labeled groups — decisions needed, on track, watch items — with a one-line entry for each of 2-3 example matters.","tips":["Decisions first, always, with the date each is needed by.","'On track' earns one line per matter — resist the recap urge.","'Watch' means: nothing to do yet, here is the trigger that changes that."],"focus":["structure","concision"],"placeholder":"DECISIONS NEEDED: 1) Kessler — approve $150K settlement authority by Nov 4."},
    {"id":"structure-law-senior-09","level":"senior","profession":"lawyer","title":"The practice strategy memo","scenario":"As practice group leader you are proposing next year's strategy to the executive committee: exit two shrinking service lines, invest in regulatory work, add a lateral hire. Your draft narrates the year's market shifts before any proposal appears.","task":"Write the memo's governing recommendation in one sentence, then the 3 supporting sections as assertive headers.","tips":["The governing idea unites the moves: reallocate from shrinking lines to growing demand.","Each header states a move and its payoff, not a topic.","Market narrative becomes evidence inside sections, not a preamble."],"focus":["structure","impact"]},
    {"id":"structure-law-senior-10","level":"senior","profession":"lawyer","title":"SCQA for the budget ask","scenario":"You need the board to approve a 40% increase in the litigation budget. Cold, the number sounds like failure. Framed properly, it is the consequence of a situation the board already knows (revenue doubled, disputes follow revenue) and a complication they have not connected (three new matters in Q3).","task":"Write the ask as SCQA in 4 sentences ending with the specific approval you need.","tips":["Situation: facts the board already accepts.","Complication: the change that makes the old budget wrong.","The Question should be the board's, not yours; the Answer is the number and what it buys."],"focus":["structure","audience"],"placeholder":"Our revenue doubled in two years, and disputes scale with revenue."},
    {"id":"structure-law-senior-11","level":"senior","profession":"lawyer","title":"PREP: 'Why did we lose the motion?'","scenario":"The client's CFO will ask why the summary-judgment motion failed after you said it was strong. The honest answer: the judge accepted their expert's damages theory, which shifts the fight to trial. You need a spoken answer that is accountable without being a lecture.","task":"Script a PREP answer in 4-5 sentences: your point, the reason, the concrete example from the ruling, the point restated with what changes now.","tips":["Point: one factor decided this, and it changes our path, not our position.","Use one specific line from the ruling as the example — it shows command.","Close with the adjustment, so the answer ends forward-looking."],"focus":["structure","clarity"]},
    {"id":"structure-law-senior-12","level":"senior","profession":"lawyer","title":"Open issues, grouped for the CEO call","scenario":"Fourteen issues remain open on the acquisition agreement. The CEOs speak in 30 minutes to break the logjam. Your list is ordered by section number of the contract — useless for a principal-to-principal call.","task":"Group the issues into 3 buckets for the call and write the one-line framing for each bucket.","tips":["Group by how they resolve: money issues, risk-allocation issues, drafting cleanup.","Tell the CEO which bucket is worth their capital — most issues are not.","Frame each bucket with the trade that unlocks it."],"focus":["structure","audience"],"placeholder":"Three buckets: two money gaps, four risk-allocation trades, and eight items our teams can close without you."},
    {"id":"structure-law-senior-13","level":"senior","profession":"lawyer","title":"The compliance training outline","scenario":"You are building the annual anti-bribery training for a global sales force. Last year's deck marched through the statute's elements and lost the room in ten minutes. The material needs to be organized around the decisions salespeople actually face.","task":"Write the training's governing message and 3 module titles organized around real decision points.","tips":["Organize by their situations — gifts, agents, expediting payments — not by legal elements.","The governing message is a behavior: when in doubt, this is the rule and this is the phone number.","Titles should be questions salespeople actually ask."],"focus":["structure","audience"]},
    {"id":"structure-law-senior-14","level":"senior","profession":"lawyer","title":"The investigation report's spine","scenario":"Your internal investigation into expense fraud is complete: 40 interviews, 20,000 documents, three findings. The report draft is organized by investigative step. The audit committee needs it organized by finding, with methodology as an appendix.","task":"Write the report's one-sentence overall conclusion and the 3 finding statements that structure the body.","tips":["Findings are the architecture; process is the appendix.","Each finding: what happened, stated as a conclusion, not a topic.","Order findings by severity, and let the overall conclusion say whether this is isolated or systemic."],"focus":["structure","precision"],"placeholder":"We found deliberate expense fraud by one employee, enabled by two control gaps — not a systemic scheme."},
    {"id":"structure-law-senior-15","level":"senior","profession":"lawyer","title":"Pyramid the M&A risk summary","scenario":"The client asked for the 'top risks' of the acquisition. Your team produced eight risks of wildly different sizes, listed flat. The real message: one risk (the change-of-control consents) could delay closing; everything else is priced in.","task":"Write the governing sentence and organize the eight risks under 2-3 grouped headers beneath it.","tips":["The pyramid's top: one sentence separating the risk that matters from the rest.","Group the remainder by treatment: covered by indemnity, priced into the deal, monitor post-close.","A flat list of eight makes the client do your synthesis for you."],"focus":["structure","clarity"]},
    {"id":"structure-law-senior-16","level":"senior","profession":"lawyer","title":"The new-office proposal","scenario":"You are proposing the firm open an office in a second city where three major clients now have headquarters. Your draft to the partnership assembles enthusiasm, anecdotes, and revenue projections in no particular order.","task":"Write the proposal's governing idea and 3 supporting buckets, one sentence each.","tips":["Governing idea: the one-line business case, with the number that carries it.","Buckets partners will test: demand evidence, cost and break-even, execution risk.","Address the strongest objection inside the structure, not as an afterthought."],"focus":["structure","impact"]},
    {"id":"structure-law-senior-17","level":"senior","profession":"lawyer","title":"Twenty questions from the regulator","scenario":"The regulator's information request contains 20 questions in their order, mixing document demands, factual queries, and policy questions. Your response will be read by an examiner who forms a view of the company from its organization and tone.","task":"Write the cover letter's opening sentence and describe the 3 sections you would organize the responses into.","tips":["The cover letter frames the story the 20 answers tell — do not let the questions set the narrative.","Group by theme while keeping their numbering as cross-references.","Consistent structure across answers signals a company in control."],"focus":["structure","audience"]},
    {"id":"structure-law-senior-18","level":"senior","profession":"lawyer","title":"The oral argument to the board","scenario":"You have ten minutes to argue for self-disclosure to the board, half of whom arrived skeptical. Wandering will lose them. You need one claim, three numbered supports, and a close that lands on the decision.","task":"Write your opening sentence and the 3 signposted points as you would speak them.","tips":["Claim first, then 'three reasons' — the count is a promise that holds attention.","Order points to disarm the skeptics: their strongest doubt gets your strongest point.","The close repeats the claim and names the vote you are asking for."],"focus":["structure","impact"],"placeholder":"I'm asking you to approve self-disclosure, for three reasons."},
    {"id":"structure-law-senior-19","level":"senior","profession":"lawyer","title":"Legal, financial, reputational","scenario":"The CEO asked what the pending investigation 'really means for us.' The truthful answer sprawls across fine exposure, defense cost, customer reaction, and employee morale. Ungrouped, it sounds like panic; grouped, it sounds like command.","task":"Answer in 3 labeled sentences — legal, financial, reputational — one line each.","tips":["Force each dimension into one sentence with its number or range.","Sequence from most to least quantifiable — it steadies the listener.","End with which dimension you would manage first and why."],"focus":["structure","clarity"],"placeholder":"Legally: worst case is a fine near $2M and a compliance monitor."},
    {"id":"structure-law-senior-20","level":"senior","profession":"lawyer","title":"SCQA for the client alert","scenario":"A new appellate ruling upends how courts read non-solicitation clauses in your clients' industry. Your alert draft opens with the case caption and procedural posture — the classic law-firm opening nobody outside a firm reads.","task":"Rewrite the alert's opening as SCQA in 4 sentences aimed at client executives.","tips":["Situation: the protection clients believed they had.","Complication: the ruling that weakened it.","Question and Answer: 'is my agreement still enforceable?' — and your one-line guidance."],"focus":["structure","audience"]},
    {"id":"structure-law-senior-21","level":"senior","profession":"lawyer","title":"PREP: arbitrate or litigate, aloud","scenario":"At the pitch meeting, the prospective client's CEO asks whether they should arbitrate or litigate their distributor dispute — a test of how you think on your feet. You believe arbitration fits: confidential, faster, and their contract already provides for it.","task":"Script a PREP answer in 4 sentences you could deliver without notes.","tips":["Point: arbitrate — commit before you explain.","Pick the reason that matches their stake (confidentiality for a brand-sensitive client).","A one-line example from a past matter is your proof; then restate and stop talking."],"focus":["structure","concision"]},
    {"id":"structure-law-senior-22","level":"senior","profession":"lawyer","title":"Ten pages into one","scenario":"Your associate's memo on successor-liability risk is thorough and unusable: ten pages, conclusion on page nine. The client gets one page. The skeleton you need: conclusion, three risk drivers, recommended protections.","task":"Write the one-page version's 4 section headers as full assertive sentences.","tips":["The conclusion header does the memo's whole job in one line.","Three drivers maximum — merge or cut the rest.","Keep the ten-pager as the appendix for the one reader who wants it."],"focus":["structure","concision"],"placeholder":"Bottom line: the asset purchase structure shields you from their liabilities, with two exceptions."},
    {"id":"structure-law-senior-23","level":"senior","profession":"lawyer","title":"The settlement-authority request","scenario":"You need the client's board to pre-authorize settlement authority up to $3M before mediation. Your draft explains the mediation process at length. The board needs a decision memo: the ask, the basis for the number, what happens with and without authority.","task":"Structure the request as an ask plus 3 supporting sections, writing one sentence for each.","tips":["Ask first, with the number and the date it is needed.","Basis section: how the $3M maps to verdict range and defense cost.","The 'without authority' section is your quiet persuader — spell out the cost of a failed mediation."],"focus":["structure","precision"]},
    {"id":"structure-law-senior-24","level":"senior","profession":"lawyer","title":"The RFP narrative arc","scenario":"Your firm's RFP response for a bank's litigation panel reads like a directory: practice descriptions, bios, representative matters. Winning responses tell one story — we know your risk profile and here is how we would run your book — with everything else as proof.","task":"Write the response's one-sentence governing narrative and the 3 proof sections beneath it.","tips":["The narrative must be about their book of litigation, not your firm.","Convert bios and matters into proof of the specific claims you make.","Cut anything that supports no claim — directories do not win panels."],"focus":["structure","audience"]},
    {"id":"structure-law-senior-25","level":"senior","profession":"lawyer","title":"The post-matter debrief","scenario":"The two-year dispute is over — a strong settlement after a rocky start. The client asked for a debrief. Your draft is a chronology, which forces the client to relive the rocky start rather than extract the lessons.","task":"Structure the debrief as one governing takeaway plus 3 lesson headers, one sentence each.","tips":["Lead with the takeaway that shapes their next dispute, not the history.","Group lessons by what the client controls: contracts, escalation timing, document habits.","A debrief structured by lessons gets you the next matter; a chronology gets filed."],"focus":["structure","impact"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-law-senior-01","level":"senior","profession":"lawyer","title":"De-legalese the client email","scenario":"Your draft to a client opens: 'Please be advised that, pursuant to our engagement letter dated March 3, we have undertaken a review of the aforementioned agreement and set forth herein our preliminary observations.' Thirty-two words, zero content.","task":"Rewrite the opening in under 12 words that say something.","tips":["'Please be advised that' advises nothing — delete it on sight.","'Pursuant to,' 'aforementioned,' 'herein' — replace each with the plain word or nothing.","Start where the content starts: what you reviewed and what you found."],"focus":["concision","clarity"],"placeholder":"We reviewed the supply agreement. Three issues need your attention."},
    {"id":"concise-law-senior-02","level":"senior","profession":"lawyer","title":"Halve the board update","scenario":"Your six-sentence board update on the regulatory matter repeats the exposure figure twice, hedges every assessment, and closes by summarizing itself. The content fits in three sentences.","task":"Rewrite the update in 3 sentences with no repeated information.","tips":["Say each fact exactly once — repetition reads as padding, not emphasis.","One hedge per judgment, maximum; pick your best.","Cut the closing summary: a three-sentence message needs no recap."],"focus":["concision","structure"]},
    {"id":"concise-law-senior-03","level":"senior","profession":"lawyer","title":"The hedge stack","scenario":"Your draft advice reads: 'It would seem that, arguably, the indemnity provision could potentially be construed as possibly covering this type of claim.' Five hedges guarding one thought. The client cannot act on it.","task":"Rewrite as one sentence with a single, honest qualifier.","tips":["Pick one calibrated hedge — 'likely,' 'probably not' — and delete the rest.","Stacked hedges do not add precision; they subtract meaning.","If you genuinely cannot commit, say what you would need to know to commit."],"focus":["concision","precision"],"placeholder":"The indemnity likely covers this claim, though"},
    {"id":"concise-law-senior-04","level":"senior","profession":"lawyer","title":"The engagement-letter cover note","scenario":"Your cover email for a new engagement letter runs nine sentences: how pleased the firm is, the history of the discussions, a preview of the letter's contents, and finally the ask — sign and return.","task":"Rewrite the cover note in 3 sentences ending with the ask and date.","tips":["One sentence of warmth is plenty.","Do not preview a document the reader is about to open.","End on the action: sign by when, return how."],"focus":["concision","clarity"]},
    {"id":"concise-law-senior-05","level":"senior","profession":"lawyer","title":"Kill the meta-commentary","scenario":"Your memo opens: 'This memorandum will first discuss the relevant statutory framework, then analyze its application to the present facts, and finally set forth our recommendations.' A table of contents wearing a paragraph's clothes.","task":"Replace the roadmap paragraph with a one-sentence opening that states the conclusion.","tips":["Announcing what you will say is not saying it.","The conclusion is the roadmap: readers navigate by knowing where you land.","If the memo needs a map, use headers — not prose about prose."],"focus":["concision","structure"],"placeholder":"The statute does not apply to this transaction, for two reasons."},
    {"id":"concise-law-senior-06","level":"senior","profession":"lawyer","title":"The airport-gate status","scenario":"The CEO texts from an airport gate: 'quick status on the lawsuit?' She has two minutes and a phone. Your fingers start typing the paragraph you would put in a memo.","task":"Write the status in 2 sentences under 35 words total.","tips":["One sentence of state, one of what happens next.","No citations, no matter names beyond the one she used.","If a decision is coming, name the date — that is the part she must not miss."],"focus":["concision","clarity"],"placeholder":"Depositions done; their case looks weaker than expected. Settlement talks likely next month — nothing needed from you until then."},
    {"id":"concise-law-senior-07","level":"senior","profession":"lawyer","title":"The doublets habit","scenario":"Your termination letter draft is full of inherited pairs: 'cease and desist,' 'null and void,' 'due and payable,' 'terms and conditions.' In a client-facing letter each pair is one word doing the work of two.","task":"Rewrite this sentence keeping one word per pair: 'The agreement is null and void, all amounts due and payable are forgiven, and both parties shall cease and desist from further performance.'","tips":["Legal doublets are historical habit, not precision — one word usually carries the meaning.","Keep a pair only where the two words genuinely differ in legal effect.","Shorter sentences survive being read aloud to a judge — a good test."],"focus":["concision","precision"]},
    {"id":"concise-law-senior-08","level":"senior","profession":"lawyer","title":"The demand letter wind-up","scenario":"Your settlement demand's cover note spends four sentences on the strength of your client's case before stating the demand. Opposing counsel skims for one number and one date, and your wind-up buries both.","task":"Rewrite the cover note in 2-3 sentences: demand, deadline, consequence.","tips":["The number and the date are the letter — everything else is decoration.","Strength arguments belong in the enclosure, stated once.","A short demand reads as confidence; a long one reads as doubt."],"focus":["concision","impact"],"placeholder":"Our client will resolve all claims for $850,000 if accepted by June 14."},
    {"id":"concise-law-senior-09","level":"senior","profession":"lawyer","title":"The 'are we exposed?' one-liner","scenario":"The CFO stops you after a meeting: 'That vendor bankruptcy — are we exposed?' The full answer involves setoff rights, an unpaid invoice, and prepayments at risk. You get one sentence before her next meeting.","task":"Write the one-sentence answer, with the follow-up offer built in.","tips":["Net it out: the single dollar figure at risk after offsets.","One sentence can hold a number, a direction, and a next step — no more.","Precision under compression is the senior skill; do not round away the meaning."],"focus":["concision","precision"]},
    {"id":"concise-law-senior-10","level":"senior","profession":"lawyer","title":"Nominalization surgery","scenario":"Your compliance update reads: 'The implementation of the remediation plan is in progress, and the completion of the documentation of new procedures is expected shortly.' Every action is frozen into a noun.","task":"Rewrite the sentence with people doing things, in under 20 words.","tips":["Un-freeze the nouns: implementation → we are implementing; completion → we will finish.","Name who acts — nominalizations hide the actor, which readers notice.","'Shortly' is not a date; give one."],"focus":["concision","clarity"],"placeholder":"We're rolling out the remediation plan and will finish documenting the new procedures by"},
    {"id":"concise-law-senior-11","level":"senior","profession":"lawyer","title":"The firm bio, halved","scenario":"The pitch deck's firm-overview paragraph runs 120 words: founding year, office count, practice breadth, awards, and a commitment-to-excellence sentence. The prospective GC will spend eight seconds on it.","task":"Rewrite the paragraph in under 50 words, keeping only what this client would care about.","tips":["Keep the one or two facts relevant to their matter; cut the rest without mercy.","Awards survive only if this buyer would recognize and value them.","'Commitment to excellence' sentences are the first cut in any draft."],"focus":["concision","audience"]},
    {"id":"concise-law-senior-12","level":"senior","profession":"lawyer","title":"One caveat, kept","scenario":"Your opinion email carries five protective qualifiers: assuming the documents are complete, subject to further review, based on current law, absent contrary facts, without independent verification. One of them actually matters for this client: the documents came from the counterparty.","task":"Rewrite the advice keeping only the caveat that matters, stated plainly.","tips":["Boilerplate caveats train clients to skip all caveats — including the real one.","State the live caveat as a fact with a consequence, not a disclaimer.","Move true boilerplate to the engagement terms, where it already lives."],"focus":["concision","precision"],"placeholder":"One caveat that matters: we've only seen the documents their side provided."},
    {"id":"concise-law-senior-13","level":"senior","profession":"lawyer","title":"The 100-word regulatory alert","scenario":"The new beneficial-ownership reporting rule affects most of your corporate clients. Your team's draft alert runs 600 words. The version that gets read — and forwarded — fits in 100.","task":"Write the 100-word version: who is affected, what to do, deadline, contact.","tips":["One sentence per job: affected test, obligation, date, penalty, contact.","Cut background entirely — link to it instead.","Every sentence a client could act on stays; every sentence about the rule's history goes."],"focus":["concision","audience"]},
    {"id":"concise-law-senior-14","level":"senior","profession":"lawyer","title":"Deposition instructions, unpadded","scenario":"Your witness-prep sheet says: 'It is generally advisable that, to the extent possible, you endeavor to limit your responses to the specific question that has been posed by examining counsel.' The witness needs rules he can remember under stress.","task":"Rewrite the instruction as one imperative sentence under 10 words.","tips":["Instructions under stress must be memorizable — a rule per breath.","'It is generally advisable that' is fear talking; write the rule.","Test each instruction: could the witness repeat it back word for word?"],"focus":["concision","clarity"],"placeholder":"Answer only the question asked, then stop."},
    {"id":"concise-law-senior-15","level":"senior","profession":"lawyer","title":"Forty words for the board slide","scenario":"The board slide on the investigation currently holds 130 words of prose. Directors read slides in five seconds while you talk. You get 40 words: status, exposure, next milestone.","task":"Write the slide's 40 words.","tips":["Fragments are legal on slides — cut subjects and articles.","One number per line; the range, the date, the milestone.","If it needs a caveat, it goes in your spoken track, not on the slide."],"focus":["concision","impact"]},
    {"id":"concise-law-senior-16","level":"senior","profession":"lawyer","title":"Subject line surgery","scenario":"Your client alert's subject line reads: 'Update Regarding Recent Regulatory Developments Affecting Data Processing Agreements and Related Compliance Considerations.' Nobody opens that. The content: new rule, contracts must be amended by October 1.","task":"Write a subject line under 10 words and a first line under 15 that together carry the whole message.","tips":["Subject = obligation + deadline; that is what earns the open.","The first line should work as the entire message if nothing else gets read.","'Update regarding' and 'considerations' are subject-line filler — always."],"focus":["concision","impact"],"placeholder":"Subject: Your data contracts need amending by Oct 1"},
    {"id":"concise-law-senior-17","level":"senior","profession":"lawyer","title":"The throat-clearing call opener","scenario":"You open advice calls with: 'Thanks for making time — I know how busy things are on your end. Before I get into the details, let me give a bit of background on how we approached this.' Ninety seconds gone; nothing conveyed.","task":"Write the first two sentences you would say instead, getting to the advice immediately.","tips":["One beat of greeting, then the headline — busy clients hear delay as doubt.","'Let me give some background first' means you are about to bury the point.","State the conclusion, then offer the background as optional: 'happy to walk through how we got there.'"],"focus":["concision","impact"]},
    {"id":"concise-law-senior-18","level":"senior","profession":"lawyer","title":"The background section nobody reads","scenario":"Your advice memo's 'Background' section runs a full page restating facts the client sent you last week. The client knows their own facts; the section exists from habit and fear.","task":"Replace the page with a 2-sentence background that states only what the advice turns on.","tips":["Keep only the facts your conclusion depends on — they double as your assumptions.","Label them as assumptions: it protects you better than a page of recap.","The client's own facts, repeated back at length, bill time and cost trust."],"focus":["concision","precision"],"placeholder":"This advice turns on two facts you've confirmed: the notice was sent May 2, and"},
    {"id":"concise-law-senior-19","level":"senior","profession":"lawyer","title":"The hallway merger question","scenario":"The CEO catches you at the elevator: 'Where are we on the merger?' The full answer spans regulatory clearance, the disclosure schedules, and a financing condition. The elevator takes twenty seconds.","task":"Write the 2-sentence spoken answer.","tips":["Lead with the date the CEO cares about: when we close.","Name the one item that could move that date — nothing else qualifies for the elevator.","Offer the fuller update as a follow-up, not a hostage."],"focus":["concision","clarity"],"placeholder":"On track to close March 31. The only thing that could move it is the regulator's second request — I'll know by Friday."},
    {"id":"concise-law-senior-20","level":"senior","profession":"lawyer","title":"Duplicate caveats in the opinion","scenario":"Your draft opinion email states the same limitation three ways: 'based solely on the documents provided,' 'we have not independently verified the facts,' and 'our review was limited to the materials furnished.' Three sentences, one thought.","task":"Merge the three into one sentence and state the conclusion it modifies.","tips":["Three phrasings of one limitation signal anxiety, not rigor.","Attach the caveat directly to the conclusion it limits — orphaned caveats protect nothing.","Ask what the caveat changes for the reader; if nothing, it may not belong at all."],"focus":["concision","precision"]},
    {"id":"concise-law-senior-21","level":"senior","profession":"lawyer","title":"The email chain, netted out","scenario":"A partner forwards you a 14-message chain with 'thoughts?' The chain nets out to: client wants to assign the contract, counterparty consent is required, counterparty is stalling to extract a fee. Your reply should not make the next reader relive the chain.","task":"Write a 3-bullet summary of the chain, one line per bullet, then your one-line recommendation.","tips":["Summarize the state, not the sequence — nobody needs the message-by-message.","One bullet per fact that matters going forward.","Your recommendation is the reason you were forwarded the chain; do not leave it out."],"focus":["concision","structure"]},
    {"id":"concise-law-senior-22","level":"senior","profession":"lawyer","title":"The invoice dispute reply","scenario":"A major client's GC emailed disputing three line items on last month's invoice, cc'ing the CFO. Your drafted defense of the billing runs 200 words per item. Long defenses of invoices read as guilt.","task":"Write a reply under 60 words that addresses the dispute and proposes a resolution.","tips":["Concede fast where they are right — it buys credibility on where they are wrong.","One sentence per line item; no narrative of the work performed.","Propose the call before the correspondence war starts."],"focus":["concision","audience"],"placeholder":"You're right on the research charge — we'll credit it."},
    {"id":"concise-law-senior-23","level":"senior","profession":"lawyer","title":"Passive voice in the findings","scenario":"Your investigation summary reads: 'Payments were approved without documentation, controls were overridden, and concerns that had been raised were not escalated.' The passives hide exactly what the audit committee must know: who.","task":"Rewrite the sentence in active voice, naming roles (not names) as actors.","tips":["Every passive in a findings document is a decision — make it consciously or not at all.","Use roles when names are premature: 'the regional controller approved...'","Active voice will feel more accusatory because it is more informative; that is the job."],"focus":["concision","precision"],"placeholder":"The regional controller approved the payments without documentation, and"},
    {"id":"concise-law-senior-24","level":"senior","profession":"lawyer","title":"Three paragraphs of 'we should discuss'","scenario":"Your email asking the client to discuss a settlement counteroffer runs three paragraphs of context before proposing a call 'at their convenience sometime this week.' The counteroffer expires Thursday at noon.","task":"Rewrite the email in 3 sentences with the deadline doing the scheduling.","tips":["The expiry is the message — put it in sentence one.","Propose two specific times; 'at your convenience' delays decisions with deadlines.","Context enough to decide: their number, your read, one line each."],"focus":["concision","impact"]},
    {"id":"concise-law-senior-25","level":"senior","profession":"lawyer","title":"'What keeps you up at night?'","scenario":"A board member asks you, as GC, what keeps you up at night. It is a two-sentence-answer moment, and the honest answer is the aging customer contracts with unlimited liability. The instinct to survey all risks would waste the moment.","task":"Write the 2-sentence answer.","tips":["Pick one risk — the question is a test of judgment, not inventory.","Sentence two is what you are doing about it; worry without a plan alarms boards.","Compression signals command: the shorter the answer, the more they trust you have thought about it."],"focus":["concision","impact"],"placeholder":"One thing: about 40 legacy customer contracts with no liability cap."}
  ],
  "precision-and-evidence": [
    {"id":"precision-law-senior-01","level":"senior","profession":"lawyer","title":"'Significant exposure' means what, exactly","scenario":"Your risk memo to the board says the litigation carries 'significant exposure' and a 'meaningful chance' of an adverse outcome. The board's next question is always the same: how much, and how likely. Vague intensifiers force a follow-up you could have pre-empted.","task":"Rewrite the assessment with a dollar range and a probability band.","tips":["Replace 'significant' with the number: $8-12M, not a mood.","Replace 'meaningful chance' with a band you will stand behind: 'roughly 40%.'","If you cannot quantify, say what you would need to — that is still more precise than 'significant.'"],"focus":["precision","impact"],"placeholder":"Realistic exposure is $8-12M, with roughly a 40% chance of an adverse verdict."},
    {"id":"precision-law-senior-02","level":"senior","profession":"lawyer","title":"The settlement recommendation with no math","scenario":"You are recommending the client accept a $3M settlement, but your memo says only that trial is 'risky' and settlement is 'prudent.' A CFO cannot approve $3M on adjectives; she needs the expected-value case laid out.","task":"Write 2-3 sentences justifying the number with a verdict range and probability.","tips":["Show the arithmetic: verdict range times odds, plus defense cost saved.","One concrete comparison (a similar case's outcome) beats three 'prudent's.","Name what the $3M buys: certainty, confidentiality, an end to the bleed."],"focus":["precision","impact"]},
    {"id":"precision-law-senior-03","level":"senior","profession":"lawyer","title":"So what, and now what","scenario":"Your case update tells the client that the court set a trial date, the other side added a new expert, and discovery closed. Three facts, no interpretation. The client reads it and asks, 'okay — so what does that mean for us?'","task":"Rewrite the update running each fact through What, So What, Now What.","tips":["Every fact needs its consequence attached — a bare fact is homework you gave the client.","'So what' is your read; 'now what' is the action or decision it triggers.","If a fact has no so-what, cut it — it is noise dressed as an update."],"focus":["precision","clarity"],"placeholder":"They added a damages expert (what), which signals they expect to reach trial (so what), so we should retain our rebuttal expert now (now what)."},
    {"id":"precision-law-senior-04","level":"senior","profession":"lawyer","title":"The skeptic-test opinion","scenario":"You are advising the CEO the company can proceed with the layoff plan without triggering federal notice requirements. A skeptical CEO — or a plaintiff's lawyer later — will ask exactly which numbers you relied on. Your draft asserts the conclusion without anchoring it.","task":"Write the conclusion with the specific factual thresholds it rests on.","tips":["State the number that controls: the rule triggers at X employees; you are at Y.","Anchor every legal conclusion to the fact that drives it.","Write it so a hostile reader cannot ask 'based on what?' — the 'what' is already there."],"focus":["precision","impact"]},
    {"id":"precision-law-senior-05","level":"senior","profession":"lawyer","title":"'Soon' is not a date","scenario":"Your update to the client promises the regulator will 'likely respond soon,' the deal will close 'in the near term,' and the appeal will be decided 'in due course.' Three timelines, zero dates. The client is trying to plan a board meeting around these.","task":"Rewrite the three timelines with actual dates or defensible date ranges.","tips":["'Soon' costs you nothing and the client everything — give a date or a range.","Where you truly cannot know, give the date by which you WILL know.","A dated estimate you later revise beats a vague one you never have to."],"focus":["precision","clarity"],"placeholder":"The regulator typically responds within 60 days, so expect their answer by mid-August."},
    {"id":"precision-law-senior-06","level":"senior","profession":"lawyer","title":"The data-breach numbers slide","scenario":"You are briefing the board on a breach. Your draft says 'a large number of records may have been affected' and notification 'could be costly.' The forensics report actually gives you 240,000 records and a per-record notification cost. Precision is available; you are hiding from it.","task":"Rewrite the two statements using the real figures and a total.","tips":["'A large number' when you know it is 240,000 reads as evasion.","Multiply it out: records times cost equals the notification line the board must approve.","Precision here is also protection — a documented number shows diligence."],"focus":["precision","impact"],"placeholder":"240,000 records were affected; at roughly $4 per record, notification runs about $960K."},
    {"id":"precision-law-senior-07","level":"senior","profession":"lawyer","title":"One insight from the discovery dump","scenario":"Document review turned up 40,000 emails and your team wants to send the client a status report full of volume statistics: pages reviewed, custodians processed, review pace. The one thing that matters is buried: three emails show the defendant knew about the defect.","task":"Write a 2-sentence update that leads with the insight, not the volume.","tips":["Volume metrics are your effort, not the client's news — subordinate them.","The insight is the smoking-gun emails; state what they prove.","One insight the client can act on beats ten statistics they cannot."],"focus":["precision","impact"]},
    {"id":"precision-law-senior-08","level":"senior","profession":"lawyer","title":"Quantify the compliance gap","scenario":"Your audit-committee report says the company has 'gaps' in its vendor-screening controls and 'many' contracts lack the required clause. The committee cannot size the remediation from 'many.' You have the actual counts.","task":"Rewrite the finding with specific counts and a share of the total.","tips":["'Many' is a placeholder for a number you have; supply it.","Give both the count and the denominator: 340 of 900 contracts.","A percentage tells the committee whether this is a fire or a cleanup."],"focus":["precision","clarity"],"placeholder":"340 of our 900 active vendor contracts — 38% — are missing the required screening clause."},
    {"id":"precision-law-senior-09","level":"senior","profession":"lawyer","title":"The 'strong case' claim, evidenced","scenario":"You told the client their case is 'strong' in the pitch. Now they ask you to back it. Restating 'strong' louder will not do; you need the two or three specific facts that make it strong and the one that makes it not airtight.","task":"Write 2-3 sentences replacing 'strong' with the evidence behind the assessment.","tips":["Name the facts driving your confidence — the contract term, the admission, the timeline.","Include the one weakness; a 'strong case' with no acknowledged risk reads as sales.","Attach a probability so 'strong' means something checkable."],"focus":["precision","impact"]},
    {"id":"precision-law-senior-10","level":"senior","profession":"lawyer","title":"The fee estimate that hides the assumptions","scenario":"You quoted the client 'roughly $400K' for the litigation. When the bill hits $650K they will remember the number, not the caveats you never stated. The estimate assumed no appeal, standard discovery, and one expert — assumptions you should have made visible.","task":"Rewrite the estimate as a number tied to its three key assumptions.","tips":["An estimate without its assumptions is a promise you did not mean to make.","State what moves the number: appeal, discovery volume, expert count.","Give a range, not a point — a single figure invites a single expectation."],"focus":["precision","clarity"],"placeholder":"We estimate $400-500K, assuming no appeal, normal discovery volume, and a single expert; each of those, if it changes, moves the number."},
    {"id":"precision-law-senior-11","level":"senior","profession":"lawyer","title":"'The regulator seemed concerned'","scenario":"After the regulator meeting, you report to the CEO that the examiner 'seemed concerned' about pricing and 'didn't love' the disclosures. The CEO must decide whether to self-report based on your read, and 'seemed concerned' is not a foundation for a decision.","task":"Rewrite your read of the meeting with specific, observable evidence for each impression.","tips":["Ground each impression in what was actually said or asked — the question they returned to twice.","Distinguish what you observed from what you inferred; label the inference.","'Seemed concerned' is a feeling; 'asked for three years of pricing data' is evidence."],"focus":["precision","clarity"]},
    {"id":"precision-law-senior-12","level":"senior","profession":"lawyer","title":"The redline summary with no counts","scenario":"You send the client a summary of the counterparty's redlines: they made 'numerous changes,' some 'concerning' and others 'minor.' The client's GC needs to triage and cannot do it from adjectives. You have the actual list.","task":"Rewrite the summary sorting the changes by count and materiality.","tips":["Give the number of changes and how many actually matter — 3 of 47.","Materiality is a fact, not a feeling: which changes shift risk or money.","Let the client spend attention where the substance is, not across all 47."],"focus":["precision","structure"],"placeholder":"They made 47 changes; 3 matter — the indemnity cap, the termination right, and the governing law."},
    {"id":"precision-law-senior-13","level":"senior","profession":"lawyer","title":"So-what on the win","scenario":"You report that the court excluded the plaintiff's key expert. To you this is huge; to the client it is a sentence of Latin-adjacent procedure. Without the so-what, the client cannot tell whether to celebrate or worry.","task":"Write a 2-sentence update: the ruling, then what it does to the case.","tips":["State the consequence in the client's currency: their damages case just lost its number.","The ruling is the 'what'; the shift in settlement leverage is the 'so what.'","Quantify the shift if you can — 'this likely cuts their demand in half.'"],"focus":["precision","impact"],"placeholder":"The court excluded their damages expert — which means they now have no admissible way to prove their $20M number."},
    {"id":"precision-law-senior-14","level":"senior","profession":"lawyer","title":"The probability you won't say","scenario":"The CEO asks flat out: 'What are our odds of winning at trial?' You want to retreat to 'it's hard to say' and 'many factors.' The CEO is making a bet-the-company decision and deserves a number with a confidence note, not a dodge.","task":"Write a 2-sentence answer that gives a probability and what it depends on.","tips":["Give a band — '55-65%' — rather than hiding behind 'hard to say.'","Name the one factor that would move it most, so the number has a lever.","A stated probability you revise is more useful than a refusal to estimate."],"focus":["precision","impact"]},
    {"id":"precision-law-senior-15","level":"senior","profession":"lawyer","title":"'Industry standard' with no anchor","scenario":"You advise the client that their proposed indemnity cap is 'below industry standard' and they should push for 'market terms.' The client's response: which market, whose standard, what number? Your advice needs an anchor they can negotiate to.","task":"Rewrite the advice with a specific benchmark and target.","tips":["'Market' is only useful with a source and a figure: caps in these deals run 1-2x fees.","Give the target number, not just the direction.","Cite what you are anchoring to — deal databases, comparable transactions, your own book."],"focus":["precision","clarity"],"placeholder":"In deals this size, liability caps typically run 1-2x annual fees; you're being offered 0.5x, so push toward 1.5x."},
    {"id":"precision-law-senior-16","level":"senior","profession":"lawyer","title":"The investigation's numbers","scenario":"Your fraud-investigation summary says a 'substantial sum' was misappropriated 'over an extended period' involving 'several' transactions. The audit committee is deciding on disclosure and clawback; 'substantial' and 'several' will not support either decision.","task":"Rewrite the finding with the amount, the timespan, and the transaction count.","tips":["Every vague quantifier here maps to a fact you have: dollars, months, transactions.","Precision drives the committee's decisions — disclosure thresholds are numeric.","'Substantial' protects no one; the documented figure protects everyone."],"focus":["precision","impact"],"placeholder":"Approximately $2.3M was misappropriated across 14 transactions over 19 months."},
    {"id":"precision-law-senior-17","level":"senior","profession":"lawyer","title":"Now-what on the new regulation","scenario":"Your client alert explains a new rule in accurate detail and stops. Clients read it, understand the rule, and still email asking 'so what do we actually do?' The alert delivered 'what' and 'so what' but skipped 'now what.'","task":"Add a 2-3 sentence 'now what' to the alert: the specific actions clients must take and by when.","tips":["Analysis without an action step is an invitation to call and ask.","List the concrete steps: amend these contracts, update this policy, by this date.","Sequence the actions and date them — a to-do list, not a reflection."],"focus":["precision","clarity"]},
    {"id":"precision-law-senior-18","level":"senior","profession":"lawyer","title":"The 'we're confident' with no basis","scenario":"Your response to the client's worried CEO says the firm is 'very confident' the contract is enforceable. The CEO has been burned by confident lawyers before. Confidence asserted is worthless; confidence sourced is persuasive.","task":"Rewrite to replace the assertion of confidence with the two facts that justify it.","tips":["Do not tell the CEO you are confident — show her why she should be.","Two specific facts (signed by an authorized officer, clear governing-law clause) beat any adjective.","Name the one thing that could undercut it, if anything — hedged confidence is credible confidence."],"focus":["precision","impact"]},
    {"id":"precision-law-senior-19","level":"senior","profession":"lawyer","title":"The comparison that needs a baseline","scenario":"You tell the board the new litigation matter is 'more serious' than the last one. Board members who did not follow the last one have no baseline. 'More serious' needs an axis and a number to mean anything.","task":"Rewrite the comparison with the dimension and figures on both sides.","tips":["Say more serious along what axis: exposure, likelihood, reputational reach.","Give both numbers — 'that one risked $2M, this one risks $15M.'","A comparison without a baseline is a feeling; with one, it is analysis."],"focus":["precision","impact"],"placeholder":"This is roughly seven times the exposure of the Kessler matter — $15M versus $2M — with similar odds."},
    {"id":"precision-law-senior-20","level":"senior","profession":"lawyer","title":"The skeptic in the deposition prep","scenario":"You are prepping the CEO to testify that the company acted 'reasonably' and 'in good faith.' Opposing counsel will demand specifics. If the CEO can only offer adjectives, the deposition unravels. He needs the concrete facts that make 'reasonable' true.","task":"Write 2-3 specific factual answers the CEO can give when pressed on 'what made that reasonable?'","tips":["Behind every conclusory word must sit a fact the witness can state under oath.","Coach facts, not characterizations: 'we obtained three quotes,' not 'we were careful.'","The skeptic test: could a hostile lawyer poke a hole? If the fact is real, no."],"focus":["precision","impact"]},
    {"id":"precision-law-senior-21","level":"senior","profession":"lawyer","title":"The billing narrative that says nothing","scenario":"The client's GC flagged your invoice narratives as too vague: entries read 'attention to case matters' and 'various correspondence.' Vague entries invite write-downs and erode trust. Each entry should show a skeptical reader real work.","task":"Rewrite two sample entries with the specific task, subject, and output.","tips":["Name the actual task and its subject: 'drafted opposition to motion to dismiss, sections I-III.'","Vague entries read as padding even when the work was real.","Precision in billing is a trust instrument, not just a compliance chore."],"focus":["precision","clarity"],"placeholder":"Drafted and revised opposition to the motion to dismiss, argument sections I-III (2.4 hrs)."},
    {"id":"precision-law-senior-22","level":"senior","profession":"lawyer","title":"'Recent developments' in the diligence report","scenario":"Your acquisition diligence report flags 'recent litigation' and 'some regulatory attention' at the target. The client is pricing a $200M deal off your report and needs dates, case counts, and dollar figures — not 'recent' and 'some.'","task":"Rewrite the two flags with counts, dates, and exposure figures.","tips":["'Recent' is a date you have; 'some' is a count you have.","Diligence exists to convert vague concern into priced risk — do the conversion.","Give the exposure per item so the client can adjust the price precisely."],"focus":["precision","impact"]},
    {"id":"precision-law-senior-23","level":"senior","profession":"lawyer","title":"The trend that needs the data","scenario":"You warn the executive committee that employment claims against the company are 'trending up' and the firm is seeing 'a lot more' of them. A committee will ask: up from what, over what period. Your assertion needs the series behind it.","task":"Rewrite the warning with the actual counts across a defined period.","tips":["A trend is two or more numbers over time — supply them: 4, then 7, then 11 per year.","State the period so 'up' has an axis.","A quantified trend justifies the budget ask that a vague one cannot."],"focus":["precision","impact"],"placeholder":"Employment claims went from 4 in 2023 to 11 last year — nearly triple in two years."},
    {"id":"precision-law-senior-24","level":"senior","profession":"lawyer","title":"So-what-now-what on the appellate ruling","scenario":"An appellate court issued a ruling that changes how a key clause in your clients' standard contracts will be enforced. Your first draft explains the holding accurately and leaves clients to work out the implications themselves.","task":"Write a 3-sentence alert: the ruling (what), the effect on existing contracts (so what), the required action (now what).","tips":["Move cleanly through the three beats; do not stop at the holding.","'So what' localizes it to their contracts; 'now what' tells them to amend or re-paper.","Date the action — a now-what without a deadline gets deferred forever."],"focus":["precision","clarity"]},
    {"id":"precision-law-senior-25","level":"senior","profession":"lawyer","title":"The one number the board remembers","scenario":"You have twelve minutes to brief the board on the entire litigation portfolio, and your draft is dense with figures. Boards remember one number. You need to decide what that number is — total exposure, worst-case, or expected cost — and make it land.","task":"Write the single sentence carrying the one number you want the board to remember, with its meaning.","tips":["Choose the number that best supports the decision you want — worst-case or expected differ sharply.","Say what the number is, not just its size: 'expected total cost,' not 'exposure.'","One anchored number beats a slide of figures the board will forget by the elevator."],"focus":["precision","impact"],"placeholder":"If you remember one number: our expected total litigation cost this year is about $9M."}
  ],
  "executive-presence": [
    {"id":"presence-law-senior-01","level":"senior","profession":"lawyer","title":"The menu that ducks the call","scenario":"The board asked what to do about the class action. Your memo lays out three options — fight, settle, mediate — with balanced pros and cons for each, and stops. The board hired you to have a view, and a neutral menu tells them you are hiding from the decision.","task":"Rewrite the close to state your recommendation and the one reason it beats the alternatives.","tips":["Presenting options without a pick is abdication dressed as thoroughness.","Keep the options, but end with 'we recommend X' and why.","One sentence on why the runner-up loses shows you weighed them, not dodged them."],"focus":["impact","structure"],"placeholder":"Of the three, we recommend early mediation: it caps the downside without the cost of a two-year fight."},
    {"id":"presence-law-senior-02","level":"senior","profession":"lawyer","title":"Fact and judgment, tangled","scenario":"Your memo to the CEO weaves together what the contract says, what the court is likely to do, and what you think the company should do — all in one undifferentiated flow. The CEO cannot tell your certainties from your bets, which is exactly what she needs to weigh the advice.","task":"Rewrite a key paragraph separating the fact, the legal judgment, and your recommendation into distinct statements.","tips":["Label the layers: 'The contract requires X' (fact) is not 'a court would likely find Y' (judgment).","Your recommendation is a third thing again — flag it as yours.","Executives calibrate trust by seeing which parts are solid and which are your call."],"focus":["precision","clarity"]},
    {"id":"presence-law-senior-03","level":"senior","profession":"lawyer","title":"The signposted board briefing","scenario":"You have eight minutes with the board on the regulatory settlement. Without structure you will ramble and lose them. You need to open by telling them the shape of what is coming so they can follow — the verbal equivalent of headings.","task":"Write the first two sentences that signpost the briefing: your recommendation and the three points you will make.","tips":["Signpost first: 'I'll cover the deal, the cost, and the one risk — and I recommend we take it.'","Naming the structure up front lets a busy room track you.","Lead with the recommendation so the three points are heard as support, not suspense."],"focus":["structure","impact"],"placeholder":"I recommend we accept the settlement. Three things: what it costs, what it closes, and the one risk it leaves open."},
    {"id":"presence-law-senior-04","level":"senior","profession":"lawyer","title":"Owning the call the client won't like","scenario":"The client wants to fire back publicly at the journalist. Your judgment is that silence is stronger, but you soften it into 'you might consider staying quiet, though of course it's your decision.' The hedge makes you sound uncertain about advice you are actually sure of.","task":"Rewrite the advice owning the recommendation while leaving the decision with the client.","tips":["'You might consider' undersells a firm view — say what you would do.","Owning the recommendation and respecting the client's authority are compatible: 'I recommend X; the call is yours.'","Confidence in the advice is what they are paying for; do not launder it into a suggestion."],"focus":["impact","audience"]},
    {"id":"presence-law-senior-05","level":"senior","profession":"lawyer","title":"The apology that isn't the point","scenario":"You are opening a difficult update to a major client where the firm missed a filing deadline (no harm done, but a miss). Your draft opens with three sentences of apology before any facts. Presence means owning it cleanly and moving to what you are doing about it.","task":"Write a 2-3 sentence opening that owns the miss once and pivots to the fix.","tips":["Apologize once, specifically, then move — repeated apology reads as flailing.","State what you have already done to contain it; action restores confidence faster than contrition.","Own it in the first person: 'we missed it,' not 'the deadline was missed.'"],"focus":["impact","clarity"],"placeholder":"We missed the extension deadline. There's no harm — I confirmed the filing is still timely under the backup date — and here's how I've made sure it can't recur."},
    {"id":"presence-law-senior-06","level":"senior","profession":"lawyer","title":"The recommendation the committee can adopt","scenario":"The audit committee needs a decision on whether to expand the internal investigation. Your memo reviews the considerations at length and ends with 'the committee may wish to consider expanding the scope.' That passive non-recommendation gives the committee nothing to vote on.","task":"Rewrite the closing as a clear recommendation the committee can adopt or reject.","tips":["'May wish to consider' is the sound of a lawyer avoiding ownership.","Give a motion they can pass: 'We recommend expanding the scope to include the EU subsidiary.'","A crisp recommendation is easier to adopt AND easier to push back on — both serve the committee."],"focus":["impact","structure"]},
    {"id":"presence-law-senior-07","level":"senior","profession":"lawyer","title":"Steady in the crisis call","scenario":"A data breach broke overnight and you are on an emergency call with a rattled C-suite. Your instinct under pressure is to talk fast and cover every contingency. Presence here is the opposite: fewer words, clear sequence, visible control.","task":"Write the first three sentences you would say to steady the room and set the agenda.","tips":["Slow the room: name where we are, what we know, what we decide today.","Short declarative sentences project control; qualifiers and speed project panic.","Give the room a structure to hold onto — the calm is the strategy."],"focus":["impact","structure"],"placeholder":"Here's where we stand. We know the scope, we have counsel engaged, and there are three decisions we need to make in the next hour."},
    {"id":"presence-law-senior-08","level":"senior","profession":"lawyer","title":"The pitch that lists instead of recommends","scenario":"In the pitch meeting, the prospective client asks how you would handle their dispute. You recite the options available to them — the classic lawyer move. What wins the work is a point of view: here is what we would do and why.","task":"Write a 2-3 sentence answer that leads with your recommended approach, not the menu.","tips":["Buyers hire conviction; a menu says 'you decide,' which is what they wanted to outsource.","State the approach and the one reason it fits their situation specifically.","You can note the alternative exists in one clause — then commit."],"focus":["impact","audience"]},
    {"id":"presence-law-senior-09","level":"senior","profession":"lawyer","title":"'I think maybe we should probably'","scenario":"Reviewing your own draft advice, you count the softeners: 'I think,' 'maybe,' 'probably,' 'it seems,' 'sort of.' Each one shaves confidence off a recommendation you actually hold firmly. The client reads the softeners, not your resume.","task":"Rewrite a hedged recommendation stripping the reflexive softeners while keeping genuine uncertainty honest.","tips":["Cut reflexive hedges ('I think,' 'sort of'); keep calibrated ones ('likely,' 'in most cases').","Distinguish real uncertainty from verbal habit — only the first earns a qualifier.","Say it once, plainly: 'we should file the motion,' not 'I think maybe we should probably file.'"],"focus":["concision","impact"]},
    {"id":"presence-law-senior-10","level":"senior","profession":"lawyer","title":"The disagreement with the CEO","scenario":"The CEO has decided to proceed with the deal structure you think is a mistake. In the room, you need to register your dissent clearly without either caving or grandstanding. Presence is disagreeing with authority while staying useful.","task":"Write the 2-3 sentences you would say to state your disagreement and your recommendation, then support the decision.","tips":["State the disagreement plainly and once — mumbled dissent protects no one.","Give the recommendation and the specific risk you see, then stop arguing.","Close by committing to execute the decision made — presence includes graceful loss."],"focus":["impact","audience"]},
    {"id":"presence-law-senior-11","level":"senior","profession":"lawyer","title":"The one-page recommendation memo","scenario":"The executive committee will decide whether to acquire a competitor's product line based partly on your legal read. You have a page. The temptation is to fill it with analysis; presence is spending the page on a recommendation with three ranked supports.","task":"Write the memo's opening recommendation sentence and the three ranked support headers.","tips":["Lead with the recommendation; the committee reads top-down.","Rank the supports by weight, not by legal category — strongest first.","Analysis lives under the headers, not in place of a recommendation."],"focus":["structure","impact"],"placeholder":"We recommend proceeding with the acquisition, subject to two closing conditions. Three reasons, strongest first:"},
    {"id":"presence-law-senior-12","level":"senior","profession":"lawyer","title":"Fact versus fear in the risk memo","scenario":"Your risk memo describes a 'terrifying' exposure and a 'nightmare' discovery scenario. The adjectives are your anxiety leaking onto the page. The board needs your assessment of the facts, cleanly separated from your emotional read of them.","task":"Rewrite a paragraph replacing the emotional coloring with the facts and a calibrated risk statement.","tips":["Strip the fear words; state the exposure and the probability instead.","If the risk is genuinely high, the numbers say so — you do not need 'nightmare.'","Calm precision reads as command; emotional language reads as loss of it."],"focus":["precision","impact"]},
    {"id":"presence-law-senior-13","level":"senior","profession":"lawyer","title":"The signposted deposition-strategy call","scenario":"You are walking the client's GC through the deposition strategy for five witnesses. Without structure, five witnesses blur together and the GC loses the thread. You need to frame the call so each segment is clearly marked.","task":"Write the opening that signposts the call: your overall strategy in one line, then the three groups the witnesses fall into.","tips":["State the through-line first: what all five depositions are meant to establish.","Group the witnesses so the GC can hold five in three buckets.","Signposting a call is presence — it shows you have already organized the chaos."],"focus":["structure","clarity"]},
    {"id":"presence-law-senior-14","level":"senior","profession":"lawyer","title":"The recommendation under a bad set of choices","scenario":"Every option on the regulatory matter is unattractive: pay a fine, litigate for years, or accept a monitor. The client wants you to tell them there is a clean path. Presence is recommending the least-bad option honestly, without pretending it is good.","task":"Write a 2-3 sentence recommendation that owns the trade-off instead of hiding it.","tips":["Do not oversell a bad-but-best option — name what it costs.","Recommend clearly anyway: 'the fine is the least-bad path, and here's why.'","Acknowledging the downside builds the trust that makes the recommendation land."],"focus":["impact","audience"],"placeholder":"None of these is good. My recommendation is to accept the fine — it's the only option that ends this within the year, and here's the price we pay for that:"},
    {"id":"presence-law-senior-15","level":"senior","profession":"lawyer","title":"Presence in three seconds of silence","scenario":"In the board meeting, a director asks a hard question and you do not have the answer instantly. Your instinct is to fill the silence with words while you think. Presence is the pause — taking a beat, then answering deliberately, rather than talking to buy time.","task":"Write the composed 2-sentence response you would give after a deliberate pause, including how you handle the part you must check.","tips":["A short pause reads as thoughtfulness; a stream of filler reads as scrambling.","Answer what you can firmly; flag what you must verify with a date, not an apology.","'Let me be precise about that' buys the beat without surrendering the room."],"focus":["impact","clarity"]},
    {"id":"presence-law-senior-16","level":"senior","profession":"lawyer","title":"The client wants a yes-man","scenario":"A powerful client wants you to bless an aggressive tax position you consider a real risk. The easy move is to validate it and keep the relationship warm. Presence — and long-term trust — comes from delivering the honest read even when it is not what they want.","task":"Write the 2-3 sentences that deliver your genuine assessment and preserve the relationship.","tips":["Lead with the honest conclusion, not with reassurance you do not believe.","Frame the candor as service: 'you're paying me to tell you this, so:'.","Offer the defensible alternative — presence solves, it does not just refuse."],"focus":["impact","audience"]},
    {"id":"presence-law-senior-17","level":"senior","profession":"lawyer","title":"The recommendation email that trails off","scenario":"Your email recommending the client accept the settlement builds well, then ends with 'let me know your thoughts' — surrendering the momentum right at the decision point. A strong close asks for the decision, not for reactions.","task":"Rewrite the closing to drive to the decision with a specific ask and timeline.","tips":["'Let me know your thoughts' invites drift; ask for the decision you want.","Name the deadline the decision faces so the ask has teeth.","End on the recommendation restated, then the ask — not on an open shrug."],"focus":["impact","concision"],"placeholder":"My recommendation is to accept. Can you confirm by Thursday so we can respond before their offer expires?"},
    {"id":"presence-law-senior-18","level":"senior","profession":"lawyer","title":"Judgment labeled as such","scenario":"Advising the board on whether the CEO's planned public statement creates legal risk, you state your view as if it were settled law: 'this statement is fine.' It is actually your judgment call on a gray area. Presence includes being clear about the confidence level of your own view.","task":"Rewrite the advice distinguishing what the law clearly permits from where you are exercising judgment.","tips":["Do not dress a judgment call as a bright-line rule — it will burn you if it goes wrong.","Say 'this is my judgment, and here's how confident I am' where the law is gray.","Labeling judgment as judgment is a mark of seniority, not weakness."],"focus":["precision","impact"]},
    {"id":"presence-law-senior-19","level":"senior","profession":"lawyer","title":"The recommendation to walk away","scenario":"After months of negotiation, your judgment is that the client should walk away from the deal — the counterparty's terms have become unacceptable. Nobody wants to hear that after this much investment. Presence is delivering the unwelcome recommendation with conviction.","task":"Write a 2-3 sentence recommendation to walk, owning the call despite the sunk cost.","tips":["Name the sunk-cost trap directly — it is the objection in the room.","Recommend walking clearly; a hedged 'we could walk' invites more months.","Give the one term that crossed the line, so the recommendation has a spine."],"focus":["impact","clarity"],"placeholder":"I know we've put months into this, but my recommendation is to walk. Their new indemnity demand shifts a risk we can't accept, and no amount of further negotiation fixes that."},
    {"id":"presence-law-senior-20","level":"senior","profession":"lawyer","title":"The 'to be honest' tell","scenario":"You catch yourself prefacing your real advice with 'to be honest' and 'candidly.' The phrases imply the rest of what you say is not honest, and they signal you are bracing to say something hard rather than just saying it. Presence is not needing the wind-up.","task":"Rewrite a piece of advice that had a 'to be honest' preface so the candor is in the substance, not the label.","tips":["Delete 'to be honest' — then make the sentence itself carry the directness.","The wind-up phrase is a request for permission to be direct; you do not need it.","Directness lives in the claim, not in an announcement that you are about to be direct."],"focus":["concision","impact"]},
    {"id":"presence-law-senior-21","level":"senior","profession":"lawyer","title":"The recommendation that survives the follow-up","scenario":"You recommend the client counter at $2M. Presence is not just stating the number — it is stating it in a way that anticipates 'why not $1.5M?' and answers it in the same breath, so your recommendation stands under the first push.","task":"Write the recommendation with the number and the one-line rationale that pre-empts the obvious pushback.","tips":["A number without a rationale invites haggling with you instead of them.","Bake in the answer to the likeliest counter-question.","Owning the specific number signals you did the analysis, not just picked a figure."],"focus":["impact","precision"],"placeholder":"Counter at $2M — not lower — because below that we signal we'll take less, and their own internal reserve is around $2.5M."},
    {"id":"presence-law-senior-22","level":"senior","profession":"lawyer","title":"The all-hands the CEO asked you to lead","scenario":"With the general counsel role comes visibility. The CEO asked you to address the whole company about the new compliance program. Reading the policy aloud will lose them; presence is owning the message and telling them why it matters to their work.","task":"Write the opening 3 sentences: what you're announcing, why it matters to them, and the one thing you're asking of them.","tips":["Own the message as yours, not the policy's — speak, don't recite.","Translate compliance into their stakes: what protects them and the company.","End the opening on the one behavior you want, stated as a request to peers."],"focus":["audience","impact"]},
    {"id":"presence-law-senior-23","level":"senior","profession":"lawyer","title":"The neutral report the partner wanted a view on","scenario":"The managing partner asked whether the firm should take on a controversial client. Your memo lays out reputational, financial, and conflict considerations evenhandedly and stops short of a recommendation. The partner asked you because they wanted your judgment, not a balanced sheet.","task":"Add the recommendation the memo is missing: your call and the deciding factor.","tips":["A balanced analysis that dodges the conclusion answers the wrong question.","State your recommendation and name the single factor that tipped it.","Presence is being willing to be wrong on the record — commit."],"focus":["impact","structure"]},
    {"id":"presence-law-senior-24","level":"senior","profession":"lawyer","title":"Composure when the client is angry","scenario":"A major client's CEO is furious about an adverse ruling and is taking it out on you on the phone. Matching his heat loses the room; collapsing loses his respect. Presence is absorbing the anger, acknowledging it, and redirecting to what happens next.","task":"Write the 2-3 sentences you would say to acknowledge the frustration and steer to the path forward.","tips":["Acknowledge the anger without absorbing blame you do not own.","Do not argue the merits mid-fury — name the feeling, then pivot to action.","A calm, structured next step is what re-establishes you as the person in control."],"focus":["impact","audience"],"placeholder":"You have every right to be frustrated — this isn't the outcome any of us wanted. Here's what I'd do next, and why it puts us in a stronger position than it looks right now."},
    {"id":"presence-law-senior-25","level":"senior","profession":"lawyer","title":"The recommendation that names its own risk","scenario":"You are recommending the board approve a novel contract structure that saves money but has never been tested in your jurisdiction. Presence is recommending it AND stating the risk plainly — not burying the novelty to make the recommendation look safer than it is.","task":"Write a 2-3 sentence recommendation that owns both the upside and the untested risk.","tips":["Lead with the recommendation, then name the risk in the same breath — hiding it destroys trust when it surfaces.","Quantify both sides: the savings and the odds the structure gets challenged.","A recommendation that names its own risk is more persuasive, not less — it reads as honest."],"focus":["impact","precision"]}
  ],
  "answering-under-pressure": [
    {"id":"pressure-law-senior-01","level":"senior","profession":"lawyer","title":"'Are we going to lose?'","scenario":"Mid-meeting, the CEO cuts in: 'Just tell me — are we going to lose this case?' Your instinct is to explain the six factors that make it complicated. She asked a yes/no-ish question and deserves a direct answer before the nuance.","task":"Write a 2-sentence answer that gives your honest read first, then the one caveat.","tips":["Answer the question asked before you complicate it — lead with the probability.","One caveat, attached to the answer, not five before it.","'It's complicated' as a first response reads as a dodge, even when it's true."],"focus":["clarity","impact"],"placeholder":"More likely than not, we win — I'd put it around 60-40 in our favor. The one thing that could flip it is"},
    {"id":"pressure-law-senior-02","level":"senior","profession":"lawyer","title":"The board member who challenges your number","scenario":"You told the board the exposure is roughly $10M. A director pushes back: 'Last quarter you said $6M — which is it?' The defensive move is to justify the old number. The strong move is to answer the change with specifics.","task":"Write a 2-3 sentence response that explains the increase with concrete drivers, not defensiveness.","tips":["Don't defend the old estimate; explain what changed to move it.","Name the specific development: 'their new expert added a $4M damages theory.'","Concede that estimates move with facts — that is candor, not weakness."],"focus":["precision","impact"]},
    {"id":"pressure-law-senior-03","level":"senior","profession":"lawyer","title":"The 'I don't know' you have to say","scenario":"In the deposition-strategy call, the client asks whether a particular document will be admissible. You genuinely do not know yet — it turns on a ruling that hasn't happened. Pretending certainty here would be malpractice; the skill is saying 'I don't know' with a path.","task":"Write a 2-sentence answer that admits the uncertainty and commits to how and when you'll resolve it.","tips":["'I don't know' is a complete and respectable answer — when paired with a next step.","Say what the answer depends on and when you will have it.","Fake certainty on an admissibility call is the kind that ends up in a malpractice claim."],"focus":["clarity","impact"],"placeholder":"Honestly, I don't know yet — it turns on how the judge rules on the privilege motion. I'll have a firm answer by the 15th, and here's what I'm doing to shape it."},
    {"id":"pressure-law-senior-04","level":"senior","profession":"lawyer","title":"The question behind the question","scenario":"The CFO asks, 'How long will the litigation take?' What she actually needs to know is whether it will be resolved before the fundraising round in Q3. Answering the literal question misses the real one. Under pressure, hear the question behind the question.","task":"Write a 2-3 sentence answer that addresses both the timeline and the concern driving it.","tips":["Answer the literal question, then the one underneath it.","Name the deadline she cares about and speak to it directly.","Anticipating the real concern signals you understand her world, not just the case."],"focus":["audience","clarity"]},
    {"id":"pressure-law-senior-05","level":"senior","profession":"lawyer","title":"The regulator's pointed question","scenario":"In a meeting with the regulator, the examiner asks directly: 'Did anyone at the company know about this before the filing?' Anything evasive reads as consciousness of guilt. You must answer precisely, truthfully, and without volunteering beyond the question.","task":"Write the 2-sentence answer that responds directly and precisely without over-answering.","tips":["Answer exactly what was asked — no more, no less — and truthfully.","Precision protects: 'to my knowledge, X' is honest and bounded.","Evasion in front of a regulator is worse than the fact you are evading."],"focus":["precision","clarity"]},
    {"id":"pressure-law-senior-06","level":"senior","profession":"lawyer","title":"'Why is this costing so much?'","scenario":"The client's GC, frustrated, demands: 'Why has this case cost double what you estimated?' The weak answer lists everything your team did. The strong answer owns the drivers, distinguishes what you controlled from what you didn't, and gives him a way forward.","task":"Write a 2-3 sentence answer that explains the overrun with specific drivers and offers control going forward.","tips":["Separate what drove cost that you controlled from what the other side or the court imposed.","Own your share plainly; deflecting all of it reads as evasion.","End with a lever he can pull — a budget cap, a scope trim — not just an explanation."],"focus":["precision","audience"]},
    {"id":"pressure-law-senior-07","level":"senior","profession":"lawyer","title":"The hostile question in the town hall","scenario":"At the employee town hall about the lawsuit, someone asks pointedly: 'Are our jobs at risk because of this?' Legal caution says deflect. But a non-answer here spreads more fear than the truth would. You must answer honestly within what you can say.","task":"Write a 2-3 sentence answer that is honest, reassuring where truthful, and clear about what you can't discuss.","tips":["Answer the fear directly — dodging it confirms it.","Say what you truthfully can ('this doesn't affect operations or headcount'), and name what you can't discuss and why.","Never say anything you would not repeat under oath — but do say something."],"focus":["audience","clarity"]},
    {"id":"pressure-law-senior-08","level":"senior","profession":"lawyer","title":"The client interrupts with a different question","scenario":"You are three sentences into explaining the settlement mechanics when the CEO interrupts: 'Just tell me what I'm signing and what happens if they breach.' You must abandon your prepared explanation and answer the two questions he actually asked.","task":"Write a 2-3 sentence answer to his two questions, dropping your original thread.","tips":["Answer the question asked, not the one you prepared — adaptability is the skill.","Take his two questions in order, one crisp answer each.","Do not circle back to your interrupted point unless he asks — he redirected for a reason."],"focus":["clarity","audience"]},
    {"id":"pressure-law-senior-09","level":"senior","profession":"lawyer","title":"'You said this would settle'","scenario":"The client is angry: 'You told me this would settle by now, and it hasn't.' You did say settlement was likely, and it hasn't happened. The defensive move is to relitigate what you actually said. The strong move is to own the miss and reassess honestly.","task":"Write a 2-3 sentence response that acknowledges the miss and gives an honest updated read.","tips":["Own that your prediction was off — quibbling over your exact words loses trust.","Give the honest reason it hasn't settled and the revised outlook.","End forward: what changes your approach now, not what you meant three months ago."],"focus":["clarity","impact"]},
    {"id":"pressure-law-senior-10","level":"senior","profession":"lawyer","title":"The board wants a guarantee","scenario":"A director presses: 'Can you guarantee we won't face criminal exposure?' You cannot guarantee that, and saying you can would be reckless. The pressure is to reassure; the skill is honest calibration that still gives the board something solid to hold.","task":"Write a 2-3 sentence answer that refuses the false guarantee while conveying your genuine assessment.","tips":["Never give a guarantee you cannot back — but do not hide behind that refusal.","Replace 'I can't guarantee' with your actual read: 'the risk is low, and here's why.'","Name what would raise the risk, so your low assessment is credible and monitored."],"focus":["precision","impact"],"placeholder":"I can't guarantee it — no honest lawyer could. What I can tell you is that the criminal risk here is low, for two specific reasons, and here's the one thing that would change my view."},
    {"id":"pressure-law-senior-11","level":"senior","profession":"lawyer","title":"The rapid-fire diligence Q&A","scenario":"In the acquisition's final diligence session, the buyer's counsel fires ten questions in five minutes about your client's contracts. Some you can answer, some you must check. Under this pace, the trap is to guess to keep up. The skill is to answer cleanly and flag the checks without losing tempo.","task":"Write how you'd handle a question you don't have the answer to, keeping pace without guessing.","tips":["A confident 'I'll confirm that by end of day' keeps tempo without guessing.","Guessing in diligence creates reps and warranties problems — never fill a gap with a hope.","Batch your 'I'll check' items so the pace doesn't break, then deliver on all of them."],"focus":["precision","clarity"]},
    {"id":"pressure-law-senior-12","level":"senior","profession":"lawyer","title":"'Whose side are you on?'","scenario":"You've delivered advice the client doesn't want — the contract doesn't say what they hoped. The CEO snaps: 'Whose side are you on here?' The pressure is to soften your read. The skill is to answer the challenge while holding the honest analysis.","task":"Write a 2-3 sentence response that reaffirms your loyalty and your honest read at the same time.","tips":["Reframe: telling the hard truth IS being on their side.","Do not retreat from the analysis under emotional pressure — that would be the real betrayal.","Pivot from the contract's limits to what you can do about them."],"focus":["audience","impact"],"placeholder":"I'm entirely on your side — which is exactly why I'm not going to tell you the contract says something it doesn't. Here's what it does give us to work with:"},
    {"id":"pressure-law-senior-13","level":"senior","profession":"lawyer","title":"The unexpected question in the pitch","scenario":"In the pitch, the prospective GC asks something off-script: 'What's a matter you lost, and what did you learn?' You could deflect to a win. The stronger move — and the one that wins trust — is to answer the actual question with a real loss and a real lesson.","task":"Write a 3-4 sentence answer that names a genuine setback and the lesson, without spinning it into a humblebrag.","tips":["Answer the question asked — evading it reads as having something to hide.","Pick a real loss with a real lesson; a fake-humble 'I cared too much' fools no one.","Land on what you do differently now — that is what they are testing for."],"focus":["clarity","audience"]},
    {"id":"pressure-law-senior-14","level":"senior","profession":"lawyer","title":"The compound question from opposing counsel","scenario":"You are representing a witness, and opposing counsel asks your client a compound, assumption-loaded question in the deposition. But separately, the client's CEO later asks YOU a similarly loaded question: 'So we broke the law and now we're just hoping they don't notice?' You must unpack the false premise before answering.","task":"Write a 2-3 sentence answer that separates and corrects the buried assumption, then addresses the real question.","tips":["Do not answer a loaded question on its own terms — name the false premise first.","Correct the assumption plainly: 'We didn't break the law; here's what actually happened.'","Then answer the legitimate concern underneath the loaded framing."],"focus":["precision","clarity"]},
    {"id":"pressure-law-senior-15","level":"senior","profession":"lawyer","title":"'Give me a number right now'","scenario":"The CEO wants a settlement authority number before a call starting in ten minutes and won't accept 'I need to analyze it.' You have a rough basis but not a polished one. The skill is to give a defensible number now with its confidence level, not to stall.","task":"Write a 2-sentence answer that gives a number under pressure with an honest confidence caveat.","tips":["Give the number you'd defend, with a band — refusing to answer helps no one on a ten-minute clock.","State your confidence: 'this is my quick read, not a full analysis.'","Commit to refining it and by when, so the fast number isn't the final word."],"focus":["precision","impact"],"placeholder":"My quick read — and I'll refine it this afternoon — is authority up to $1.5M, with a target of settling around $1.1M."},
    {"id":"pressure-law-senior-16","level":"senior","profession":"lawyer","title":"The question that assumes you failed","scenario":"A board member asks: 'Given how badly this was handled, what are you going to do to fix it?' The premise — that you handled it badly — is contested. You must address the real concern without either accepting a false premise or sounding defensive.","task":"Write a 2-3 sentence response that handles the loaded premise gracefully and pivots to substance.","tips":["Acknowledge the concern without conceding a characterization you disagree with.","Correct the record briefly if you must, then move to the forward-looking answer they actually want.","Defensiveness confirms the premise; calm substance dissolves it."],"focus":["impact","audience"]},
    {"id":"pressure-law-senior-17","level":"senior","profession":"lawyer","title":"'What would you do if it were your money?'","scenario":"The founder, deciding whether to settle, asks you point-blank: 'If it were your money, what would you do?' It is a fair question that many lawyers deflect with 'it's your decision.' The skill is to give your genuine view while keeping the decision hers.","task":"Write a 2-3 sentence answer that gives your real recommendation and respects her authority.","tips":["Answer the question honestly — 'I'd settle' — the deflection is a cop-out here.","Give the one reason that drives your view, so it is a judgment, not a gut call.","Close by returning the decision to her, now better informed."],"focus":["impact","audience"],"placeholder":"If it were my money, I'd settle — the downside at trial is more than I'd want to gamble to save the difference. But it's your call, and here's the one factor that might make you weigh it differently:"},
    {"id":"pressure-law-senior-18","level":"senior","profession":"lawyer","title":"The press question in the hallway","scenario":"A reporter catches you leaving the courthouse: 'Does today's ruling mean your client is guilty?' You cannot say 'no comment' and look evasive, nor can you argue the case in the press. You need one composed sentence that says something true and safe.","task":"Write the 1-2 sentence answer you'd give a reporter under this pressure.","tips":["Have one safe, true line ready — the pressure is real-time and public.","Correct the false frame ('a procedural ruling is not a finding of guilt') without arguing the merits.","Never say anything you would not want quoted or that you would not repeat in court."],"focus":["precision","clarity"]},
    {"id":"pressure-law-senior-19","level":"senior","profession":"lawyer","title":"When you were wrong","scenario":"You advised the client a clause was enforceable, a court just held it wasn't, and the client is on the phone. The pressure is to explain why you were reasonable at the time. The skill is to own the error cleanly, then move to remedy.","task":"Write a 2-3 sentence response that owns the incorrect advice without excessive self-justification and pivots to the fix.","tips":["Own it in one sentence — 'I got that call wrong' — before any explanation.","A brief 'here's why it was a close question' is fine; a paragraph of self-defense is not.","Move fast to remedy: what you're doing now to limit the damage."],"focus":["clarity","impact"],"placeholder":"I got that call wrong, and I own it. It was a genuinely close question, but the ruling went the other way — so here's what I'm doing right now to protect your position."},
    {"id":"pressure-law-senior-20","level":"senior","profession":"lawyer","title":"The 'just yes or no' trap","scenario":"A director demands: 'Just answer yes or no — is the company at risk?' The honest answer genuinely requires a 'yes, but' — the risk exists but is manageable. You must respect the demand for directness while not letting a false binary distort the truth.","task":"Write a 2-3 sentence answer that gives the direct answer and the one qualifier that makes it accurate.","tips":["Give the yes or no first — respect the demand — then the essential qualifier.","One qualifier, not a hedge-stack; the director asked for directness for a reason.","'Yes, but manageable, and here's why' honors both the question and the truth."],"focus":["clarity","precision"],"placeholder":"Yes — but manageable. The risk is real, and here's the single thing that keeps it contained:"},
    {"id":"pressure-law-senior-21","level":"senior","profession":"lawyer","title":"The client tests your conviction","scenario":"You recommended arbitration. The CEO pushes back hard, listing reasons for court, watching to see if you'll fold. This is a test: does your recommendation survive pressure, or was it a soft preference? You must hold your view with specifics or genuinely update it.","task":"Write a 2-3 sentence response that either defends your recommendation with new specifics or honestly updates it.","tips":["If you still believe it, defend with a specific reason, not by repeating yourself louder.","If his points genuinely change the calculus, say so — updating on evidence is strength.","What loses respect is folding without reason; what wins it is a reasoned hold or a reasoned change."],"focus":["impact","precision"]},
    {"id":"pressure-law-senior-22","level":"senior","profession":"lawyer","title":"The gap in your own knowledge, exposed","scenario":"In front of the executive committee, a member asks about a tax consequence that is genuinely outside your expertise. Bluffing risks a wrong answer on the record. The skill is to acknowledge the boundary of your competence and route to who can answer.","task":"Write a 2-sentence response that admits the limit of your expertise and provides a path to the answer.","tips":["'That's outside my area' is a strength when paired with 'and here's who I'll get it from.'","Never bluff on specialist ground — a wrong confident answer is the real failure.","Commit to a specific person and timeline so the gap is a plan, not a shrug."],"focus":["clarity","impact"],"placeholder":"That's a tax question outside my area, and I won't guess at it. Let me get our tax partner on it and come back to you with a firm answer by Wednesday."},
    {"id":"pressure-law-senior-23","level":"senior","profession":"lawyer","title":"'This is your fault'","scenario":"A deal fell through and the client's CEO is blaming the legal team in front of the whole deal group. Some of the blame may be fair, some not. Under this public pressure, you must respond without either accepting undue blame or fighting in front of the room.","task":"Write a 2-3 sentence response that stays composed, owns your genuine share, and redirects to the path forward.","tips":["Don't relitigate blame in front of the group — it never lands well.","Own your real share cleanly; contest the rest privately, not in the room.","Redirect the room's energy to what happens next, which is what actually helps."],"focus":["impact","audience"]},
    {"id":"pressure-law-senior-24","level":"senior","profession":"lawyer","title":"The follow-up that catches the weak spot","scenario":"You made your recommendation to settle, and the sharpest board member asks the one question you hoped to avoid: 'What's the strongest argument against settling?' Deflecting reveals you didn't consider it. The skill is to answer your own weak spot honestly and then explain why you still recommend it.","task":"Write a 2-3 sentence answer that states the best counter-argument fairly, then why you recommend settling anyway.","tips":["Steelman the opposing view — a weak version of it fools the sharp director.","Then give the reason your recommendation survives that argument.","Answering the hard follow-up well is what earns the board's trust in the whole recommendation."],"focus":["precision","impact"]},
    {"id":"pressure-law-senior-25","level":"senior","profession":"lawyer","title":"The high-stakes 'what do you recommend?'","scenario":"In the crisis war room at 11pm, with the executive team exhausted and a regulator deadline at dawn, the CEO turns to you: 'What do we do?' Everyone is watching. There is no time for a menu. You must give a clear recommendation and the reason, calmly, right now.","task":"Write the 2-3 sentence recommendation you'd give in that room, direct and reasoned.","tips":["Under maximum pressure, a clear recommendation is a gift — give it.","One reason, stated calmly; the composure is half the message at 11pm.","End with the immediate next step so the room can move, not just nod."],"focus":["impact","clarity"],"placeholder":"Here's what we do: we file the disclosure by the deadline and get ahead of it. The alternative — waiting — costs us the one advantage we still have, which is initiative. First step tonight is"}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-law-senior-01","level":"senior","profession":"lawyer","title":"The before-and-after of settling","scenario":"You are persuading a reluctant CEO to settle. Listing the legal risks hasn't moved him. What moves decision-makers is a clear before-and-after: where the company is now (bleeding cost and attention) and where settling puts it (case closed, focus back on the business).","task":"Write a 3-4 sentence persuasion built on the contrast between the current path and the settled future.","tips":["Paint the 'now' vividly: two more years of cost, uncertainty, and executive distraction.","Then the 'after': closed, capped, and off the CEO's desk.","The gap between the two states is your argument — make it feel like a choice, not a defeat."],"focus":["impact","audience"]},
    {"id":"narrative-law-senior-02","level":"senior","profession":"lawyer","title":"Make the abstract risk concrete","scenario":"The product team keeps ignoring your warning about an unlimited-liability clause because 'unlimited liability' is an abstraction to them. Persuasion requires making it concrete: a specific scenario where one bad shipment bankrupts a product line.","task":"Write a 2-3 sentence warning that turns the abstract risk into a concrete, vivid scenario.","tips":["Abstractions don't persuade — a scene does. Give them one bad day, in detail.","Use a real number: 'one defective batch, and the claim is larger than the product's lifetime revenue.'","Concrete stakes are what make a risk feel worth acting on."],"focus":["impact","precision"],"placeholder":"Picture this: one shipment fails, a customer's factory floods, and the claim comes in at $40M — on a product line that earns $8M a year. That's what 'unlimited' means here."},
    {"id":"narrative-law-senior-03","level":"senior","profession":"lawyer","title":"Pre-empt the board's objection","scenario":"You are recommending the board approve an expensive early settlement. You know the objection: 'we look weak, and it invites more claims.' If you don't address it, a skeptic will raise it and derail you. Persuasion means naming and dismantling the strongest objection before it's spoken.","task":"Write a 2-3 sentence passage that raises the 'looks weak / invites claims' objection and answers it.","tips":["Name the objection yourself — it disarms the skeptic and shows you've thought it through.","Answer it with specifics: confidential settlement, no admission, no precedent set.","Pre-empting the best counter-argument is more persuasive than avoiding it."],"focus":["impact","structure"]},
    {"id":"narrative-law-senior-04","level":"senior","profession":"lawyer","title":"The pitch that tells a story","scenario":"You are pitching a manufacturer drowning in product-liability suits. Reciting your firm's capabilities bores them. The winning pitch tells their story: the wave they're facing, the fractured defense making it worse, and the coordinated future you'd build.","task":"Write a 3-4 sentence pitch narrative moving from their painful present to the future you'd create.","tips":["Start in their world, not your firm — the story is about them.","Name the complication making today worse: inconsistent defenses across states creating bad precedent.","End on the after-state your approach delivers, concretely."],"focus":["audience","impact"]},
    {"id":"narrative-law-senior-05","level":"senior","profession":"lawyer","title":"The self-report, framed as strength","scenario":"You're recommending the company self-report a violation to the regulator, and the executive team hears only 'confess and get punished.' Persuasion means reframing: self-reporting is taking control of the narrative before the regulator finds it and takes control from you.","task":"Write a 2-3 sentence reframe that turns self-reporting from surrender into strategic control.","tips":["Reframe the action: this is us setting the terms, not us confessing.","Contrast the two futures: we disclose on our terms, or they find it and dictate theirs.","Make the passive-looking choice feel like the aggressive, in-control one."],"focus":["impact","audience"],"placeholder":"Self-reporting isn't surrender — it's us controlling the story before they do. If we disclose, we shape the framing, the timeline, and the remedy. If they find it first, we lose all three."},
    {"id":"narrative-law-senior-06","level":"senior","profession":"lawyer","title":"The demand letter that persuades","scenario":"Your settlement demand needs to make opposing counsel actually recommend paying. A dry recitation of claims won't. It needs a short narrative that makes their client's exposure feel real and their trial outcome feel bad — before you name the number.","task":"Write a 3-sentence demand-letter passage that builds the story of their exposure before the ask.","tips":["Tell the story a jury would hear — that's the exposure you're selling.","Make one fact vivid: the document, the admission, the sympathetic plaintiff.","The narrative justifies the number; the number without the story reads as a bluff."],"focus":["impact","structure"]},
    {"id":"narrative-law-senior-07","level":"senior","profession":"lawyer","title":"Persuade the partnership to invest","scenario":"You want the partnership to fund a new regulatory practice. Partners have heard 'growth opportunity' too many times. Persuasion requires a before-and-after: the clients you're turning away now, and the book of business the investment captures.","task":"Write a 3-4 sentence pitch contrasting the missed opportunity today with the captured future.","tips":["Lead with the loss you're already taking: 'we turned away $2M in this work last year.'","Then the after: what the practice captures once funded.","Partners fund a gap they can feel, not a vision they can't."],"focus":["impact","audience"]},
    {"id":"narrative-law-senior-08","level":"senior","profession":"lawyer","title":"The stakes for a distracted client","scenario":"Your client keeps deprioritizing the document-retention overhaul you recommended. To them it's a chore. You need to make the stakes concrete: the specific way a missing retention policy turns a survivable lawsuit into a catastrophic one.","task":"Write a 2-3 sentence warning making the retention risk concrete and urgent.","tips":["Show the domino: a lawsuit lands, documents were auto-deleted, and now it's a spoliation case.","Name the multiplier: a $2M case becomes a $10M case plus sanctions.","Urgency comes from a concrete bad outcome, not from the word 'important.'"],"focus":["impact","precision"]},
    {"id":"narrative-law-senior-09","level":"senior","profession":"lawyer","title":"Reframe the loss as a position","scenario":"You lost a motion, and the client is deflated. But the loss actually clarified the battlefield — you now know exactly what you're facing at trial and can settle from a realistic position. Persuasion is reframing the setback into a strategic clarification.","task":"Write a 2-3 sentence reframe that turns the lost motion into useful strategic ground.","tips":["Acknowledge the loss honestly first — a reframe that denies reality fails.","Then find the genuine strategic gain: clarity, leverage, or a narrowed dispute.","The reframe must be true, not spin — false optimism destroys credibility."],"focus":["impact","audience"]},
    {"id":"narrative-law-senior-10","level":"senior","profession":"lawyer","title":"The objection you must name first","scenario":"You are recommending the client fight rather than settle, and you know the CFO's objection: 'litigation is unpredictable and expensive.' She's right that it is. Persuasion means conceding the valid part of her objection, then showing why fighting still wins.","task":"Write a 2-3 sentence argument that concedes the cost objection and overcomes it.","tips":["Concede what's true — pretending litigation is cheap or certain loses you.","Then show the asymmetry: settling here invites a wave of copycat claims that costs more.","A conceded-then-overcome objection is more persuasive than a denied one."],"focus":["impact","structure"]},
    {"id":"narrative-law-senior-11","level":"senior","profession":"lawyer","title":"The crisis statement's arc","scenario":"The company faces a public allegation and must issue a statement. A defensive denial reads as guilt; a groveling apology concedes too much. The persuasive statement has an arc: acknowledge the concern, state what's true, commit to a specific action.","task":"Write a 3-4 sentence public statement following the acknowledge-clarify-commit arc.","tips":["Open by acknowledging the concern is taken seriously — never dismiss it.","State the true, defensible facts plainly — no spin a court could later contradict.","Close on a concrete commitment, which is what converts a statement into trust."],"focus":["audience","impact"]},
    {"id":"narrative-law-senior-12","level":"senior","profession":"lawyer","title":"Make the compliance program matter","scenario":"You're rolling out a new anti-corruption program to a sales force that sees it as bureaucracy slowing deals. Rules don't persuade; a story does. You need the story of a peer company where one skipped check ended careers and cost hundreds of millions.","task":"Write a 3-sentence opening that uses a concrete cautionary story to make the program matter.","tips":["Lead with a specific, real-feeling consequence, not with the policy.","Make it about people like them — a salesperson, a deal, a prosecution.","Then connect: 'this program is what stands between us and that.'"],"focus":["audience","impact"]},
    {"id":"narrative-law-senior-13","level":"senior","profession":"lawyer","title":"Persuade the client to take the deal now","scenario":"A favorable settlement offer is on the table but expires Friday, and the client is inclined to wait and negotiate more. You need to persuade them to act now by making the risk of waiting concrete: the offer reflects a window that is closing.","task":"Write a 2-3 sentence persuasion that makes the cost of waiting concrete and immediate.","tips":["Name what changes Friday: the offer, and the leverage behind it.","Make the downside of waiting specific: their new expert report lands next week and hardens their position.","Urgency persuades only when the deadline is real and its consequence is named."],"focus":["impact","precision"],"placeholder":"This offer is good until Friday for a reason — their expert report lands Monday, and once it does, their willingness to pay this drops. Waiting doesn't get us more; it gets us less."},
    {"id":"narrative-law-senior-14","level":"senior","profession":"lawyer","title":"The board presentation that opens with stakes","scenario":"Your board presentation on the litigation portfolio opens with a methodology slide. Nobody leans in for methodology. A persuasive opening leads with what's at stake: the one case that could materially move the company's valuation.","task":"Write the 2-3 sentence opening that leads with stakes to earn the board's attention.","tips":["Open on what the board stands to lose or protect, not on how you did the analysis.","Name the single highest-stakes item first — that's what makes them lean in.","Methodology, if needed, comes after you've earned attention with stakes."],"focus":["impact","structure"]},
    {"id":"narrative-law-senior-15","level":"senior","profession":"lawyer","title":"Anticipate the regulator's counter","scenario":"You're preparing the company's position for a regulator meeting. You know their strongest counter-argument to your defense. Persuasion — and preparation — means building your presentation to pre-empt it, so when they raise it, you've already answered.","task":"Write a 2-3 sentence passage that raises the regulator's likely counter and neutralizes it in advance.","tips":["Identify their best argument, not their weakest — prepare against strength.","Address it proactively: 'you may be concerned about X; here's why the facts don't support it.'","Pre-empting their counter shows command and takes the wind out of it."],"focus":["impact","precision"]},
    {"id":"narrative-law-senior-16","level":"senior","profession":"lawyer","title":"The client who won't fund the defense","scenario":"The client is balking at the cost of a proper defense and wants to cut corners. You need to persuade them that underfunding now creates a far worse before-and-after: a cheap defense that loses, versus a full one that wins or settles well.","task":"Write a 2-3 sentence argument contrasting the false economy of a cheap defense with the real cost of losing.","tips":["Make the false economy vivid: saving $200K now to risk a $5M loss.","Contrast the two paths concretely, in their currency.","Frame the spend as insurance with a calculable payoff, not as a bill."],"focus":["impact","audience"]},
    {"id":"narrative-law-senior-17","level":"senior","profession":"lawyer","title":"The retention pitch to a wavering client","scenario":"A major client is shopping your work to cheaper firms. A defensive 'we've always done good work' won't hold them. You need a persuasive narrative: what you've built together, what's at risk in a switch, and what the next chapter looks like.","task":"Write a 3-4 sentence retention narrative that moves from shared history to future value without sounding desperate.","tips":["Lead with a specific shared win, not a general claim of loyalty.","Name the concrete risk of switching: institutional knowledge, ramp-up cost, continuity mid-matter.","End on forward value, so it reads as confidence, not pleading."],"focus":["audience","impact"]},
    {"id":"narrative-law-senior-18","level":"senior","profession":"lawyer","title":"Make 'reasonable doubt' concrete for the jury story","scenario":"You're explaining to the client's board why your trial narrative will work. Abstract legal standards won't convince them. You need to tell them the story the jury will hear — the human version that makes your defense feel true, not just legally sufficient.","task":"Write a 3-sentence version of the story you'd tell a jury, translated for the board.","tips":["Legal standards persuade lawyers; stories persuade juries — and boards.","Anchor on a person and a moment the jury can picture.","The board needs to feel why the story works, not just be told that it does."],"focus":["impact","audience"]},
    {"id":"narrative-law-senior-19","level":"senior","profession":"lawyer","title":"Pre-empt the 'why now?' objection","scenario":"You're recommending the company update contracts it has used for a decade. The obvious objection: 'they've worked fine for ten years — why now?' If you don't answer it, the initiative dies. Persuasion means naming and answering the 'why now' before it's asked.","task":"Write a 2-3 sentence passage that raises the 'why now' objection and answers it with what changed.","tips":["Name the objection: 'these have worked for ten years — so why touch them?'","Answer with the specific change: a new ruling, a new rule, a new risk that didn't exist before.","'Why now' is only persuasive to answer if something genuinely changed — name it precisely."],"focus":["impact","precision"],"placeholder":"You're right that these contracts have worked for a decade — but last month's appellate ruling changed the ground under them. What protected you for ten years now has a hole in it, and that's why this can't wait."},
    {"id":"narrative-law-senior-20","level":"senior","profession":"lawyer","title":"The comment letter that persuades the agency","scenario":"Your client wants to persuade a regulator to soften a proposed rule. A letter of complaints won't move them. A persuasive comment letter tells a story: the real businesses affected, the concrete harm the rule causes, and a workable alternative that meets the agency's goal.","task":"Write a 3-sentence persuasive core: the concrete harm, and the alternative that still serves the agency's aim.","tips":["Regulators respond to concrete harm to real parties, not to abstract objection.","Show you share their goal — then offer a better path to it.","An alternative that meets their aim persuades; a flat 'no' does not."],"focus":["audience","impact"]},
    {"id":"narrative-law-senior-21","level":"senior","profession":"lawyer","title":"The stakes of the whistleblower decision","scenario":"The audit committee is inclined to handle a whistleblower complaint quietly and internally. You believe that's a serious mistake. Persuasion means making the stakes of the wrong choice concrete: the difference between a managed disclosure and a retaliation claim plus a leak.","task":"Write a 2-3 sentence argument making the stakes of mishandling the complaint concrete.","tips":["Contrast the two futures: handled right versus the leak-and-retaliation scenario.","Name the concrete second harm — the cover-up is always worse than the thing covered.","Make the downside vivid enough that 'quietly' stops sounding safe."],"focus":["impact","audience"]},
    {"id":"narrative-law-senior-22","level":"senior","profession":"lawyer","title":"Persuade the CEO to apologize","scenario":"A mistake harmed a customer, and the CEO's instinct is to say nothing on legal advice. But here, a well-crafted apology reduces legal risk and reputational damage. You must persuade the CEO that the counterintuitive move — acknowledging fault carefully — is the stronger one.","task":"Write a 2-3 sentence persuasion that reframes the apology from legal risk into legal and reputational protection.","tips":["Address the fear head-on: 'I know the instinct is silence, but here silence costs more.'","Reframe: a careful, bounded apology defuses both the lawsuit and the story.","Give the evidence — cases or examples where acknowledgment reduced exposure."],"focus":["impact","audience"]},
    {"id":"narrative-law-senior-23","level":"senior","profession":"lawyer","title":"The before-and-after of the compliance investment","scenario":"You're asking the board to fund a compliance function they see as pure cost. Persuasion requires the before-and-after: the company today, one enforcement action away from disaster, versus the company with a program that turns a catastrophe into a manageable event.","task":"Write a 3-4 sentence pitch built on the contrast between the exposed present and the protected future.","tips":["The 'now' is exposure: one incident and the fine plus monitor plus reputation hit.","The 'after' is resilience: the same incident, but contained and defensible.","Frame the spend as buying the difference between those two futures."],"focus":["impact","structure"]},
    {"id":"narrative-law-senior-24","level":"senior","profession":"lawyer","title":"Answer the strongest case against your recommendation","scenario":"You're recommending the company litigate a contract dispute rather than settle. The strongest argument against you is that litigation will sour a valuable ongoing commercial relationship. A persuasive recommendation names that cost squarely and shows why it's still worth it.","task":"Write a 2-3 sentence passage that raises the relationship-damage objection and answers it honestly.","tips":["Name the real cost — the relationship — don't pretend it isn't at stake.","Answer with why the relationship is already damaged or worth less than the principle at issue.","Steelmanning the objection makes your recommendation credible, not weaker."],"focus":["impact","precision"]},
    {"id":"narrative-law-senior-25","level":"senior","profession":"lawyer","title":"The closing argument to the board","scenario":"You have the final word to the board on whether to pursue the acquisition despite the legal risks you've flagged. This is your closing argument: a persuasive synthesis that acknowledges the risk, tells the story of the upside, and pre-empts the strongest doubt in one coherent close.","task":"Write a 3-4 sentence closing that integrates the risk, the upside story, and the pre-empted objection into one persuasive whole.","tips":["Integrate rather than list — a closing weaves risk, reward, and rebuttal together.","Acknowledge the risk you flagged; credibility comes from not hiding it.","End on the forward-looking image of the company if it acts — the after-state the board is voting for."],"focus":["impact","structure"]}
  ],
  "delivering-hard-messages": [
    {"id":"hard-law-senior-01","level":"senior","profession":"lawyer","title":"The advice they hoped wouldn't come","scenario":"The client sank six months and real money into a strategy, and your analysis now says it won't work — the regulatory path is closed. Your instinct is to cushion it across three paragraphs. Clear is kind: the bad news should come first, cleanly, then the way forward.","task":"Write a 2-3 sentence opening that delivers the bad news up front, then pivots to options.","tips":["Front-load the hard message — burying it wastes their time and reads as evasion.","Say it plainly once: the strategy won't work, and why in one clause.","Immediately pivot to what they can do instead — clear is kind includes a path."],"focus":["clarity","impact"],"placeholder":"I have to give you news you won't like: the regulatory path we've been pursuing is closed — the new guidance forecloses it. Here's what we can still do:"},
    {"id":"hard-law-senior-02","level":"senior","profession":"lawyer","title":"The clean 'no' to a client request","scenario":"A valued client asks you to take a legal position you consider unsupportable. You want to keep the relationship, so you're tempted to give a mushy 'we'd have to look into whether that might possibly work.' A clean, respectful 'no' serves them better than a hedge that raises false hope.","task":"Write a 2-3 sentence response that says no clearly and preserves the relationship.","tips":["A clean 'no' with a reason beats a soft 'maybe' that wastes their time and money.","Say no to the request, not to the client — separate the position from the person.","Offer the alternative you can support, so 'no' comes with a door, not just a wall."],"focus":["clarity","audience"]},
    {"id":"hard-law-senior-03","level":"senior","profession":"lawyer","title":"Telling the CEO she's the problem","scenario":"Your investigation found that the CEO's own informal communications created the legal exposure. You must tell her this directly. Softening it into vague 'communications generally' language fails her and the company. Behavior, impact, ask: name the conduct, its effect, and what must change.","task":"Write a 2-3 sentence message using behavior-impact-ask to deliver this to the CEO.","tips":["Name the specific behavior factually, without accusation or euphemism.","State the impact: how those messages create legal exposure.","End with the concrete ask — what must change going forward."],"focus":["clarity","precision"]},
    {"id":"hard-law-senior-04","level":"senior","profession":"lawyer","title":"The firing of a major client","scenario":"A long-standing client has become impossible — non-paying, abusive to your team, and pushing you toward ethical lines. You've decided the firm must terminate the relationship. This message must be clear, professional, and leave no ambiguity, while remaining civil.","task":"Write a 2-3 sentence termination message that is clear, professional, and final.","tips":["State the decision plainly — 'we are terminating the engagement' — no softening that invites negotiation.","Keep the reason brief and professional; you don't need to litigate the grievances.","Cover the practical transition (file handover, effective date) so it reads as orderly, not emotional."],"focus":["clarity","impact"],"placeholder":"After careful consideration, we've decided to end our representation of you, effective [date]. This is final. To ensure a smooth transition,"},
    {"id":"hard-law-senior-05","level":"senior","profession":"lawyer","title":"The estimate you have to raise","scenario":"You quoted the client $500K for the matter; it's going to be closer to $900K. You must tell them, and the temptation is to bury the number in a fog of justification. Clear is kind: the new number first, then the honest reasons, then what you'll do to control it.","task":"Write a 2-3 sentence message leading with the revised number, then the drivers.","tips":["Lead with the number — hiding it in paragraph three insults the reader.","Own your share of the overrun honestly; deflecting all of it destroys trust.","End with control: what you're doing to cap it from here."],"focus":["clarity","precision"],"placeholder":"I need to revise our estimate upward, and I want to be straight about it: this will run closer to $900K, not $500K. The main driver was the other side's document volume, which we couldn't foresee, and here's how I'm capping it going forward:"},
    {"id":"hard-law-senior-06","level":"senior","profession":"lawyer","title":"Feedback to the underperforming partner","scenario":"A fellow partner's sloppy work on a shared matter nearly cost the firm a client. As practice leader, you must give direct feedback to a peer — delicate, but necessary. Behavior, impact, ask, delivered as a professional equal, not a scold.","task":"Write a 2-3 sentence feedback message to the partner using behavior-impact-ask.","tips":["Be specific about the behavior — the missed deadline, the unreviewed filing — not a character judgment.","Name the impact concretely: the client nearly walked.","Frame the ask as a fix between equals, and invite their side."],"focus":["clarity","audience"]},
    {"id":"hard-law-senior-07","level":"senior","profession":"lawyer","title":"The disclosure the CEO doesn't want to make","scenario":"Securities law requires disclosing the pending investigation in the next filing, and the CEO is resisting hard. You must deliver the hard message: this isn't optional, and non-disclosure is itself a serious violation. Clear and firm, without lecturing.","task":"Write a 2-3 sentence message that makes the obligation unambiguous while respecting the CEO's position.","tips":["Be unambiguous that this is a legal requirement, not your preference — soft framing invites a fight you'll lose later.","Name the second risk clearly: non-disclosure compounds the original problem.","Acknowledge the CEO's concern, then hold the line — clear is kind here."],"focus":["clarity","impact"]},
    {"id":"hard-law-senior-08","level":"senior","profession":"lawyer","title":"Declining the associate's request for the case","scenario":"A talented associate asked to run the upcoming trial, and you have to say no — she's not ready for a matter this size. A vague 'let's see' is unkind; it leaves her hoping. A clear 'no, and here's the path to yes' respects her.","task":"Write a 2-3 sentence response that declines clearly and gives her a real development path.","tips":["Say no clearly — 'not this one' — so she isn't left guessing.","Give the honest reason (the specific experience gap), not a platitude.","Attach the path: what she'd need to do to lead the next one."],"focus":["clarity","audience"]},
    {"id":"hard-law-senior-09","level":"senior","profession":"lawyer","title":"Breaking the settlement collapse to the client","scenario":"The settlement you were close to just collapsed — the other side walked, and now you're headed to a trial the client hoped to avoid. This is bad news the client will take hard. Front-load it, be honest about what it means, and give them the immediate next step.","task":"Write a 2-3 sentence message that delivers the collapse clearly and steadies the client with a next step.","tips":["Lead with the fact — the deal is off — no wind-up.","Be honest about the consequence (trial) without catastrophizing it.","Give one concrete next step so they're not left in freefall."],"focus":["clarity","impact"],"placeholder":"The settlement has fallen through — they walked away this morning. That means we're now preparing for trial, which I know isn't what you wanted. Here's exactly what happens next and why our position is still strong:"},
    {"id":"hard-law-senior-10","level":"senior","profession":"lawyer","title":"The 'no' to the board's preferred option","scenario":"The board wants to pursue an aggressive counterclaim, and you have to tell them it's a bad idea likely to backfire. Saying 'no' to a board requires delivering the hard message with respect for their authority while being unmistakably clear about your advice.","task":"Write a 2-3 sentence message that clearly advises against the counterclaim without softening it into ambiguity.","tips":["Give the clear recommendation against — a mushy version lets them proceed and blame you later.","Name the specific way it backfires, concretely.","Respect their authority to overrule you, but don't pre-soften your advice to make that easier."],"focus":["clarity","impact"]},
    {"id":"hard-law-senior-11","level":"senior","profession":"lawyer","title":"Telling the client they'll probably lose","scenario":"After full analysis, your honest read is that the client will likely lose at trial. They've been optimistic, partly because you were early on. You must deliver this hard reassessment clearly, so they can make a sound decision about settling.","task":"Write a 2-3 sentence message that delivers the pessimistic reassessment honestly and clearly.","tips":["Lead with the honest read — 'I now think we're more likely to lose than win.'","Explain what changed your view, so it's a reassessment, not a reversal out of nowhere.","Connect it to the decision it should drive: settle now from a realistic position."],"focus":["clarity","precision"]},
    {"id":"hard-law-senior-12","level":"senior","profession":"lawyer","title":"The uncomfortable conflict conversation","scenario":"You've discovered that continuing to represent both co-defendants creates a conflict, and you must tell one of them — a client you like — that you can no longer represent them. This is a hard, relationship-straining message that must be clear and prompt.","task":"Write a 2-3 sentence message that delivers the conflict-driven withdrawal clearly and preserves goodwill.","tips":["State the withdrawal clearly and the reason (a conflict) without over-explaining the mechanics.","Deliver it promptly — a delayed hard message compounds the harm.","Offer a warm handoff to competent alternative counsel — that's the kindness in clarity."],"focus":["clarity","audience"]},
    {"id":"hard-law-senior-13","level":"senior","profession":"lawyer","title":"The regulator's demand you must relay","scenario":"The regulator is demanding a consent decree with terms the CEO will hate — an independent monitor and admission of certain facts. You must relay this hard news plainly, without either sugar-coating the terms or editorializing your own dismay.","task":"Write a 2-3 sentence message that delivers the regulator's terms plainly and sets up the real decision.","tips":["State the terms cleanly and completely — don't drip them out to soften the blow.","Separate the fact (their demand) from the decision (whether to accept it).","Set up the choice ahead rather than dwelling on how bad the terms are."],"focus":["clarity","structure"],"placeholder":"The regulator has come back with their terms, and they're hard: an independent monitor for two years and an admission on the pricing facts. I want to lay them out fully, then walk through our real options — because there are more than it first looks."},
    {"id":"hard-law-senior-14","level":"senior","profession":"lawyer","title":"Correcting the CEO's public misstatement","scenario":"The CEO said something in an earnings call that's legally inaccurate and needs correcting before it becomes a bigger problem. You must tell her she got it wrong and that a correction is needed — a delicate hard message to a superior.","task":"Write a 2-3 sentence message that flags the misstatement and the needed fix without embarrassing her.","tips":["Name the specific statement and why it's a problem, factually.","Focus on the fix, not the fault — 'we need to correct this' beats 'you were wrong.'","Frame urgency around protection, not blame."],"focus":["clarity","audience"]},
    {"id":"hard-law-senior-15","level":"senior","profession":"lawyer","title":"The 'we can't help with that' to a friend-client","scenario":"A client you're personally friendly with asks the firm to handle a matter in an area where you're genuinely not competent, and taking it would be a disservice. You must decline — hard because of the friendship — clearly and without leaving the door falsely open.","task":"Write a 2-3 sentence message that declines the work clearly and refers them well.","tips":["Decline plainly — friendship makes a soft 'maybe' more tempting and more harmful.","Give the honest reason: it's outside the firm's competence, and they deserve a specialist.","Refer them to someone genuinely good — the decline and the referral together are the kindness."],"focus":["clarity","audience"]},
    {"id":"hard-law-senior-16","level":"senior","profession":"lawyer","title":"Telling the partnership about the malpractice claim","scenario":"A malpractice claim has been filed against the firm arising from your matter. You must inform the partnership — a hard message about your own exposure. Front-load it, own your part, and give the plan, resisting the urge to build a defense before stating the facts.","task":"Write a 2-3 sentence message to the partnership that leads with the fact and moves to the plan.","tips":["State the fact first — a claim has been filed — before any context or defense.","Own your involvement honestly; the partnership will trust the plan more if you do.","Move quickly to the response plan (insurer notified, counsel engaged)."],"focus":["clarity","impact"]},
    {"id":"hard-law-senior-17","level":"senior","profession":"lawyer","title":"The hard truth about the document","scenario":"Document review turned up an internal email that badly hurts the client's case, and they don't know yet. You must break it to them: this document exists, it's damaging, and it changes the strategy. Clear, prompt, and paired with what you'll do about it.","task":"Write a 2-3 sentence message that delivers the bad-document news and its strategic consequence.","tips":["Lead with the existence and gist of the document — don't ease in.","Be honest about how much it hurts; downplaying it now costs you credibility later.","Pair it immediately with the adjusted strategy — the hard news plus a plan."],"focus":["clarity","impact"],"placeholder":"We found a document in review that I need to tell you about right away: an internal email that undercuts our central argument. It's damaging, and it changes our strategy — here's how we adapt:"},
    {"id":"hard-law-senior-18","level":"senior","profession":"lawyer","title":"Denying the extension the client demands","scenario":"The client is demanding you seek yet another extension to delay an inevitable filing, and you have to tell them it's not viable — the court won't grant it and asking will hurt credibility. A clean 'no' with the reason, not a reluctant 'I'll try.'","task":"Write a 2-3 sentence response that declines to seek the extension and explains why plainly.","tips":["Say no clearly — 'I'm not going to ask for this' — an 'I'll try' you expect to fail is dishonest.","Give the real reason: the court will deny it and it damages our standing.","Redirect to the productive move instead of the delay they want."],"focus":["clarity","impact"]},
    {"id":"hard-law-senior-19","level":"senior","profession":"lawyer","title":"The performance conversation with a rainmaker","scenario":"A partner who brings in major revenue is also creating a toxic environment that's driving associates out. As managing partner you must have the hard conversation — behavior, impact, ask — with someone whose business protects them and who knows it.","task":"Write a 2-3 sentence opening for the conversation using behavior-impact-ask, holding firm despite the power dynamic.","tips":["Lead with specific behaviors, not reputation — 'in the last quarter, three associates cited X.'","State the impact plainly: attrition, cost, and firm risk, regardless of revenue.","Make the ask concrete and non-negotiable; revenue doesn't buy an exemption."],"focus":["clarity","precision"]},
    {"id":"hard-law-senior-20","level":"senior","profession":"lawyer","title":"Breaking the deal-killer to the CEO","scenario":"Due diligence found a problem serious enough that you must recommend the client walk away from an acquisition they're emotionally committed to. This is the hardest kind of message — telling someone to abandon something they want. Clear, direct, with the reason that justifies it.","task":"Write a 2-3 sentence message that delivers the walk-away recommendation clearly and gives the deciding reason.","tips":["State the recommendation to walk plainly — hedging here just prolongs the pain.","Lead with the single deal-killing fact, concretely.","Acknowledge the disappointment without letting it soften the recommendation."],"focus":["clarity","impact"],"placeholder":"I have to give you a recommendation you won't want: walk away from this deal. Diligence found an undisclosed liability that could exceed the purchase price, and no amount of renegotiation makes that safe. I know how much you wanted this, which is why I'm being this direct."},
    {"id":"hard-law-senior-21","level":"senior","profession":"lawyer","title":"The 'your position is indefensible'","scenario":"A client insists on a contract interpretation that is simply wrong, and they're about to act on it. You must tell them plainly that their position won't hold — clear is kind, because letting them proceed on a false premise is the real disservice.","task":"Write a 2-3 sentence message that tells the client their position is wrong, clearly and without cushioning it into ambiguity.","tips":["Say it directly — 'this interpretation won't hold' — a soft version lets them proceed and fail.","Give the specific reason their reading is wrong, briefly.","Redirect to the position that will hold — the correction plus the alternative."],"focus":["clarity","precision"]},
    {"id":"hard-law-senior-22","level":"senior","profession":"lawyer","title":"Telling the board a director must recuse","scenario":"A director has a conflict on the matter under discussion and must recuse — but he doesn't see it and won't like being told. You must deliver this to the board clearly: the conflict is real, recusal is required, and the reason is specific.","task":"Write a 2-3 sentence message that states the recusal requirement clearly and factually.","tips":["State the requirement plainly — recusal is necessary — not as a suggestion.","Ground it in the specific conflict, factually, so it's not personal.","Keep the tone procedural and unemotional; the facts carry the message."],"focus":["clarity","precision"]},
    {"id":"hard-law-senior-23","level":"senior","profession":"lawyer","title":"The apology for the firm's error","scenario":"Your firm made a real mistake that harmed the client's position, and you must own it directly to their GC. The temptation is to bury the admission in mitigating context. A clear, front-loaded acknowledgment of fault, then the remedy, is what rebuilds trust.","task":"Write a 2-3 sentence message that owns the firm's error clearly and moves to the remedy.","tips":["Acknowledge the error plainly and specifically before any context — front-load the ownership.","Don't over-apologize; one clear admission, then action.","Lead the remedy with what the firm is doing to fix and to prevent recurrence."],"focus":["clarity","impact"],"placeholder":"I want to be direct with you: we made a mistake. We missed the filing window on the counterclaim, and that's on us, not on any circumstance. Here's what we're doing to remedy it and to make sure it can't happen again:"},
    {"id":"hard-law-senior-24","level":"senior","profession":"lawyer","title":"The layoff legal-risk conversation with HR","scenario":"HR wants to move fast on layoffs in a way that creates real discrimination-claim exposure, and you have to slow them down with a hard message: the current plan is legally dangerous. Clear, specific, and paired with the safer path.","task":"Write a 2-3 sentence message that flags the legal danger clearly and offers the compliant alternative.","tips":["Name the specific legal risk in the current plan, not a general 'be careful.'","Be clear that the plan needs to change, not just be 'reviewed.'","Offer the compliant path so 'no' comes with a workable 'instead.'"],"focus":["clarity","precision"]},
    {"id":"hard-law-senior-25","level":"senior","profession":"lawyer","title":"The hard message that ends the relationship well","scenario":"A client is moving their work to another firm, and you're handling the transition. Separately, you have one hard truth to deliver: a lingering legal risk they should address, which their new firm may not catch. Delivering it well, with nothing to gain, is the mark of the professional.","task":"Write a 2-3 sentence message that delivers the parting warning clearly and generously, with no self-interest.","tips":["Deliver the warning plainly even though you gain nothing — that's the integrity move.","Be specific about the risk so the new firm can act on it.","Keep the tone gracious and free of any pitch to stay — the generosity is the message."],"focus":["clarity","audience"]}
  ],
  "putting-it-together": [
    {"id":"together-law-senior-01","level":"senior","profession":"lawyer","title":"The board memo, under a page limit","scenario":"The board chair gave you one page for your recommendation on the regulatory settlement — no more. You must integrate everything: lead with the recommendation, structure the support, cut the padding, and own the call, all inside the constraint.","task":"Write the full one-page memo's opening: recommendation, then three tight supporting points, in 5-6 sentences total.","tips":["Recommendation in sentence one; the page limit forbids a wind-up.","Three supports, one sentence each — structure and concision working together.","Own the call explicitly; a page this short has no room for a neutral menu."],"focus":["structure","impact"]},
    {"id":"together-law-senior-02","level":"senior","profession":"lawyer","title":"Same news, three channels","scenario":"The regulator closed its inquiry with no action. You must convey it three ways: a formal memo to the board, a two-line text to the traveling CEO, and a calm word to the anxious general counsel. Same facts, register matched to each channel.","task":"Write the CEO text (under 25 words) and the first line of the board memo, showing the register shift.","tips":["The text is bare and immediate; the memo is measured and complete.","Match formality to channel — a text that reads like a memo annoys; a memo that reads like a text alarms.","The facts stay identical; only the framing and length move."],"focus":["audience","concision"],"placeholder":"CEO text: Inquiry closed, no action. Full memo to follow. Board memo: The FCA has closed its inquiry into the company's pricing practices with no enforcement action."},
    {"id":"together-law-senior-03","level":"senior","profession":"lawyer","title":"Edit your own advice like a reader","scenario":"You've drafted a dense advice email to the client and have five minutes before sending. The senior skill is to reread it as the busy client will — skimming for the answer — and cut everything that isn't load-bearing. Edit like a reader, not a writer.","task":"Take this over-written opening and rewrite it as the client would want it: 'Further to your inquiry of last week regarding the enforceability of the non-compete provisions contained in the executive agreements, we have completed our review and are pleased to provide the following analysis for your consideration.' Rewrite in under 20 words.","tips":["Read as the client: they want the answer, not a receipt for their question.","Cut 'further to,' 'for your consideration,' and every word that isn't the answer.","Start where the content starts — the enforceability verdict."],"focus":["concision","audience"],"placeholder":"Your executive non-competes are enforceable, with one exception you should fix:"},
    {"id":"together-law-senior-04","level":"senior","profession":"lawyer","title":"The crisis email at 6am","scenario":"A story breaks overnight and the executive team needs your read before markets open. You have fifteen minutes to write one email that is clear, structured, honest about uncertainty, and ends with a recommendation — every skill at once, under real time pressure.","task":"Write the full crisis email in 5-6 sentences: what happened, your read, what's uncertain, and your recommendation.","tips":["Lead with the situation and your bottom-line read — no time to warm up.","Separate what you know from what you're still confirming; label the uncertainty.","End with a clear recommended action, even if provisional — the team needs a direction."],"focus":["structure","impact"]},
    {"id":"together-law-senior-05","level":"senior","profession":"lawyer","title":"The pitch, whole","scenario":"You have two minutes to open a pitch to a prospective client's GC. You must start where they are, tell a story of their problem, make one clear recommendation about how you'd help, and own it with presence — the whole toolkit in 120 seconds.","task":"Write the full 4-5 sentence pitch open integrating audience, narrative, and a clear recommendation.","tips":["Open in their world; earn attention before you talk about your firm.","One clear recommended approach, owned — not a menu of services.","Keep it tight enough to say in two minutes and land."],"focus":["audience","impact"]},
    {"id":"together-law-senior-06","level":"senior","profession":"lawyer","title":"The settlement recommendation, complete","scenario":"You're recommending the client settle at $2.5M. The complete message needs the recommendation up front, the numbers behind it, the strongest objection pre-empted, and a clear ask — leading, precision, persuasion, and presence in one email.","task":"Write the full recommendation email in 5-6 sentences integrating all four skills.","tips":["Recommendation and number first; expected-value math second.","Pre-empt the obvious objection ('why not fight?') in one line.","Close with the specific decision and deadline you need."],"focus":["structure","precision"],"placeholder":"I recommend we settle at $2.5M. The math: a likely verdict of $5-7M at roughly 50% odds, plus $1.5M in remaining defense cost, makes this the value play. I know the instinct is to fight, but"},
    {"id":"together-law-senior-07","level":"senior","profession":"lawyer","title":"The one-slide board update","scenario":"You get one slide and ninety seconds of talk time on the litigation portfolio at the board meeting. The slide must be ruthlessly concise; your spoken track must lead with the point, carry the structure, and end on the one thing you need. Integrate the written and spoken registers.","task":"Write the slide's headline plus 3 bullet fragments, and the first two sentences of your spoken track.","tips":["The slide is fragments; your voice supplies the sentences — don't duplicate.","Spoken track leads with the point and signposts the three items.","End the spoken open on the decision you need from the board."],"focus":["concision","impact"]},
    {"id":"together-law-senior-08","level":"senior","profession":"lawyer","title":"The client email that has to do everything","scenario":"Your client email must deliver bad news (you lost a motion), reassure without spinning, reset the strategy, and ask for a decision — hard-message delivery, honesty, structure, and a clear ask, all in one message a stressed client will skim.","task":"Write the full email in 5-6 sentences integrating the hard news, honest reassurance, new strategy, and the ask.","tips":["Front-load the bad news, then the honest 'here's what it does and doesn't change.'","Reset the strategy in one clear move, not a paragraph.","End with the specific decision you need and by when."],"focus":["structure","impact"]},
    {"id":"together-law-senior-09","level":"senior","profession":"lawyer","title":"Match the register to a hostile audience","scenario":"You're writing to opposing counsel who has been combative. The message needs to be firm, give nothing away, stay scrupulously professional, and make a specific demand — register matched to an adversary, not a client. Tone is a strategic choice here.","task":"Write a 2-3 sentence message to hostile opposing counsel that is firm, professional, and makes a clear demand.","tips":["Cool and precise beats heated — the record may be read by a judge.","Make the specific demand plainly; firmness lives in clarity, not in adjectives.","Give away no argument or emotion the other side can use."],"focus":["audience","precision"]},
    {"id":"together-law-senior-10","level":"senior","profession":"lawyer","title":"The 30-second verbal recommendation","scenario":"The CEO catches you between meetings and asks for your recommendation on the acquisition's legal risk. You have 30 seconds to deliver a complete answer: recommendation, the one key reason, and the one risk to watch — structured, owned, and precise, spoken aloud.","task":"Write the 30-second spoken recommendation (3-4 sentences) integrating everything.","tips":["Recommendation first, then the single deciding reason — no room for a menu.","One risk to watch, named precisely, so the answer is honest not rosy.","Structure it so it's followable by ear, and own it in the first person."],"focus":["structure","impact"],"placeholder":"My recommendation is to proceed, with one condition. The deal is clean except for the change-of-control consents, which we can get if we start now. The one thing I'd watch is"},
    {"id":"together-law-senior-11","level":"senior","profession":"lawyer","title":"The all-hands remarks, drafted","scenario":"The CEO asked you to speak to the whole company about the lawsuit for two minutes. You must be honest, reassuring within the truth, clear about what you can't say, and give employees the one behavior you need — audience-awareness, honesty, and presence integrated for a large, anxious room.","task":"Write the full 4-5 sentence remarks integrating acknowledgment, honest reassurance, the boundary, and the ask.","tips":["Acknowledge what they've read; don't pretend it isn't happening.","Say what's true and reassuring, name what you can't discuss and why.","End on the one thing you need from them — clear and repeatable."],"focus":["audience","impact"]},
    {"id":"together-law-senior-12","level":"senior","profession":"lawyer","title":"The memo that survives forwarding","scenario":"Your advice memo to the GC will be forwarded to the CEO, the CFO, and possibly the board — each reading at a different altitude. You must write one document that works for all of them: a clear top-line anyone can act on, with depth available below for those who want it.","task":"Write the memo's opening top-line (2 sentences any executive can act on) and name how you'd layer the detail below.","tips":["The top-line must stand alone for the skimming CEO.","Layer detail so the CFO and board can go deeper without the top-line depending on it.","Write for the highest and busiest reader first; the rest is optional depth."],"focus":["structure","audience"]},
    {"id":"together-law-senior-13","level":"senior","profession":"lawyer","title":"The negotiation email, calibrated","scenario":"You're emailing the counterparty's counsel to move a stalled negotiation. The message must be warm enough to keep the deal alive, firm enough to signal your floor, structured around a specific proposal, and free of anything that weakens your position — every skill balanced against a live counterparty.","task":"Write the 3-4 sentence negotiation email integrating warmth, firmness, a specific proposal, and no leaked weakness.","tips":["Open with enough warmth to keep it collaborative, then get specific.","Make one concrete proposal; vagueness invites stalling.","Signal your floor without begging or bluffing — calibrated firmness."],"focus":["audience","impact"]},
    {"id":"together-law-senior-14","level":"senior","profession":"lawyer","title":"The self-report memo under scrutiny","scenario":"Your memo recommending self-disclosure will be read by skeptical directors and, potentially, by a court later. It must be persuasive to the board and defensible on the record — leading, precision, and persuasion integrated, with every word chosen knowing an adversary might read it.","task":"Write the memo's opening 3-4 sentences: the recommendation, its basis, and the pre-empted objection — worded to persuade the board and hold up under later scrutiny.","tips":["Recommend clearly and support with facts, not adjectives a court could challenge.","Pre-empt the board's 'why confess?' objection with the strategic-control framing.","Write every sentence as if opposing counsel will one day quote it."],"focus":["precision","impact"]},
    {"id":"together-law-senior-15","level":"senior","profession":"lawyer","title":"The two-minute litigation-vs-settle pitch","scenario":"On a call, the client's board asks you to make the case for settling versus fighting in two minutes. You must frame the choice, give the numbers, pre-empt the 'we look weak' objection, and land a clear recommendation — narrative, precision, and presence, spoken under time pressure.","task":"Write the full 4-5 sentence spoken pitch integrating the frame, the numbers, the pre-empted objection, and the recommendation.","tips":["Frame the real choice — cost and risk of each path — before the numbers.","Give the key figures cleanly so the board can follow by ear.","Pre-empt the weakness objection, then land firmly on your recommendation."],"focus":["structure","impact"]},
    {"id":"together-law-senior-16","level":"senior","profession":"lawyer","title":"Edit the associate's memo for the client","scenario":"A brilliant but dense 8-page associate memo must become a client-ready 3-paragraph email today. You must extract the conclusion, restructure around it, cut the doctrine, translate the jargon, and add a clear recommendation — the full editing toolkit applied to someone else's work.","task":"Write the 3-paragraph client version's opening: the conclusion, the one thing that matters, and the recommendation, in 4-5 sentences.","tips":["Find and lead with the buried conclusion — usually near the end of the draft.","Cut the doctrinal exposition entirely; the client wants the answer and the action.","Add the recommendation the memo probably lacks; associates analyze, partners advise."],"focus":["concision","structure"]},
    {"id":"together-law-senior-17","level":"senior","profession":"lawyer","title":"The regulator response letter, whole","scenario":"Your response to the regulator's information request must be organized around your narrative (not their question order), precise on facts, calibrated in tone toward an audience that forms judgments from your letter, and cover the substance completely — structure, precision, and audience integrated in a high-stakes document.","task":"Write the cover letter's opening 3-4 sentences that frame the narrative, set the cooperative-but-firm tone, and preview the structure.","tips":["Frame the story your answers tell before diving into their questions.","Tone: cooperative and precise, never defensive or evasive — the examiner is your audience.","Preview the structure so the letter reads as organized command, not a scramble."],"focus":["structure","audience"]},
    {"id":"together-law-senior-18","level":"senior","profession":"lawyer","title":"The bad-news call, scripted","scenario":"You have to call the client's CEO with news that the deal has a serious new legal problem. You must front-load the bad news, be precise about what it is, own your recommendation, and steady the CEO — hard-message delivery, precision, and presence, all live on a phone call.","task":"Write the first 4-5 sentences of the call script integrating the front-loaded news, the precise problem, and the owned recommendation.","tips":["Say the hard news in the first breath — a call that buries it feels like a trap.","Be precise about the problem so the CEO isn't left imagining worse.","Own a recommendation immediately; a problem without a proposed path panics people."],"focus":["clarity","impact"],"placeholder":"I'm calling with a problem on the deal that we need to deal with today. In short: the target has an undisclosed regulatory liability that could reach $20M. It's serious, but it's not fatal — and here's what I recommend we do about it:"},
    {"id":"together-law-senior-19","level":"senior","profession":"lawyer","title":"The board Q&A, prepared and live","scenario":"You've delivered your recommendation to the board and now face live questions, including hostile ones. You must answer each question actually asked, handle pushback with specifics, admit what you don't know with a path, and hold your recommendation under pressure — pressure-handling integrating everything.","task":"Write how you'd handle this live board question, in 2-3 sentences: 'You're recommending we spend $3M to settle — how is that not just paying to make a nuisance go away?'","tips":["Answer the actual question (why the spend is justified), not a reframed easier one.","Respond to the 'nuisance' framing with specifics — the real exposure — not defensiveness.","Hold your recommendation with a reason, calmly."],"focus":["impact","precision"]},
    {"id":"together-law-senior-20","level":"senior","profession":"lawyer","title":"The client alert that gets read and forwarded","scenario":"Your firm's client alert on a new ruling competes with a hundred others in the GC's inbox. It must lead with the client's obligation, be ruthlessly concise, translate the ruling into their stake, and end with a clear action — leading, concision, audience, and precision, engineered to be opened, read, and forwarded.","task":"Write the full alert in 4-5 sentences: subject-worthy first line, the obligation, the stake, and the dated action.","tips":["First line = the obligation and deadline; that's what earns the open and the forward.","Translate the ruling into what the client must now do, not what the court held.","End with one dated action — a forwardable alert is an actionable one."],"focus":["concision","audience"],"placeholder":"Your standard employment agreements may no longer be enforceable after last week's ruling — and you have until year-end to fix them."},
    {"id":"together-law-senior-21","level":"senior","profession":"lawyer","title":"The strategy memo to the executive committee","scenario":"You're proposing the legal department's strategy for the year to the executive committee: reallocate budget, add capability, drop a vendor. It must have one governing idea, structured support, precise numbers, a clear recommendation, and pre-empt the CFO's cost objection — the whole toolkit for a persuasive strategic document.","task":"Write the memo's governing recommendation sentence, three structured supports, and the pre-empted cost objection, in 5-6 sentences.","tips":["One governing idea unifies the moves; lead with it.","Three supports with real numbers, structured, not narrated.","Pre-empt the CFO's cost concern by framing the reallocation as net-neutral or saving."],"focus":["structure","precision"]},
    {"id":"together-law-senior-22","level":"senior","profession":"lawyer","title":"The apology-and-plan to a wronged client","scenario":"The firm erred and harmed a valued client's position. Your message must own the error cleanly, avoid over-groveling, present a precise remedy, and rebuild confidence with a forward plan — hard-message honesty, concision, and presence integrated to save a relationship.","task":"Write the full 4-5 sentence message integrating the clean ownership, the remedy, and the confidence-rebuilding plan.","tips":["Own the error in the first sentence, specifically, without a wall of apology.","Present the remedy precisely — what you're doing, by when.","End forward-looking, rebuilding confidence with a concrete prevention step."],"focus":["clarity","impact"]},
    {"id":"together-law-senior-23","level":"senior","profession":"lawyer","title":"The deposition-prep briefing, whole","scenario":"You're prepping a first-time executive witness in one session. You must translate legal rules into behavior, structure the day so he can hold it, address his anxiety with presence, and be precise about the traps — audience, structure, and presence integrated to make an anxious witness effective.","task":"Write the opening 4-5 sentences of the prep briefing integrating the reassurance, the structure, and the translated core rules.","tips":["Open by steadying him — a calm witness is the whole goal.","Give the structure of the day before the rules, so he has a frame.","Translate each rule into a behavior he can remember under stress."],"focus":["audience","structure"]},
    {"id":"together-law-senior-24","level":"senior","profession":"lawyer","title":"The RFP response's winning core","scenario":"Your firm's RFP response for a major panel must tell one story about the client's book of risk, structure the proof beneath it, be precise with track-record numbers, and own a clear point of view — narrative, structure, precision, and presence integrated into a document that wins competitive work.","task":"Write the response's one-sentence governing narrative, plus the opening of its first proof section with a precise track-record figure, in 4-5 sentences.","tips":["The narrative is about their risk book, not your firm — lead there.","Structure proof beneath the narrative; every credential supports a claim you made.","Use precise numbers ('reduced their litigation spend 22% over three years'), not superlatives."],"focus":["structure","precision"]},
    {"id":"together-law-senior-25","level":"senior","profession":"lawyer","title":"The year-end letter to the board","scenario":"As general counsel you write the board a year-end letter: the legal function's state, the year's key risks handled, the risks ahead, and what you need for next year. It must integrate everything — a governing message, structure, precision, honesty about what went wrong, and a clear ask — the capstone document of the role.","task":"Write the letter's opening: the governing message, and the preview of its structure, in 4-5 sentences that set up a complete, executive-grade letter.","tips":["Open with the one-sentence state-of-the-function message the board should remember.","Preview the structure — year in review, risks ahead, the ask — so it reads as organized command.","Signal the honesty to come (including what went wrong) — a letter that only reports wins loses trust."],"focus":["structure","impact"],"placeholder":"This was the year the legal function moved from reacting to anticipating — and the numbers behind that shift are the heart of this letter. I'll cover three things: what we handled, what's coming, and what I need to meet it."}
  ],
};
